const SONGS = [{"id": 1, "batch": 1, "sheet": "範例1 А цыган идет 吉普賽人走來", "full_title": "範例1 А цыган идет 吉普賽人走來", "title_ru": "А цыган идет", "title_zh": "吉普賽人走來", "motif": "義務與激情", "analysis": {"1.1情感關鍵詞": {"指標": "思念類、渴望類詞彙", "分類": "▪ 思念類詞彙\n▪ 渴望類詞彙"}, "1.2行動關鍵詞": {"指標": "離開、向前行進的行動詞彙", "分類": "▪ 離開／留下"}, "1.3意象關鍵詞": {"指標": "自然意象為主，顏色意象次之", "分類": "▪ 自然意象\n▪ 顏色意象\n▪ 物品意象"}, "2.1敘事視角": {"指標": "第三人稱→混合視角（兩人共同）", "分類": "▪ 第三人稱（他／她）\n▪ 混合視角"}, "2.2傾訴對象": {"指標": "對聽眾（號召性呼告）", "分類": "▪ 對聽眾"}, "2.3情節發展": {"指標": "有明確情節轉折（獨行→二人同行→向四方出發）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "開放式結局（永遠向前，無終點）", "分類": "▪ 開放式結局（未知）"}, "3.1情感表現方式": {"指標": "直接高昂吶喊＋自然意象隱喻", "分類": "▪ 直接高昂吶喊／控訴\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "中度（為愛離開、漂泊流浪）", "分類": "▪ 中度：離開"}, "3.3時間維度": {"指標": "永恆性（無終點的永遠前行）", "分類": "▪ 永恆性（永遠／一生）"}, "3.4情感強度等級": {"指標": "中度（壯志豪情，非痛苦沉淪）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「тоскою」(哀愁)\n「бесприютной тоской」(無家可歸的哀愁)", "1.2行動關鍵詞": "「идёт」(走去)、「вперёд」(向前)\n「идти」(前行)\n「за любимым в ночь」(在夜晚跟隨愛人出行)", "1.3意象關鍵詞": "自然：「звезда」(遊牧之星)、「буря」(暴風)、「волна」(浪濤)、「паруса」(風帆)\n顏色：「багровеющие небеса」(血紅天空)\n物品：「тропа」(小徑)—命運之路", "2.1敘事視角": "「А цыганская дочь за любимым в ночь」(吉普賽女兒跟隨愛人)\n→「И вдвоём по тропе навстречу судьбе」(兩人共同踏上命運之路)", "2.2傾訴對象": "「Так вперёд, за цыганской звездой кочевой!」反覆出現的號召語氣，如戰歌般呼喚聽眾同行", "2.3情節發展": "吉普賽女兒獨自為愛人夜行→兩人共同面對命運→分別向落日/黎明/南緯出發", "2.4結局類型": "「Хоть на край земли, хоть за край」(哪怕到地球的盡頭，哪怕越過邊界)\n終點未明，以「繼續前行」作結", "3.1情感表現方式": "「Так вперёд!」反覆吶喊\n血紅天空、暴風如掃帚等自然意象隱喻命運壯烈", "3.2行動後果": "「А цыганская дочь за любимым в ночь, По родству бродяжьей души」\n(遵循血脈中的漂泊靈魂而離開)", "3.3時間維度": "「Хоть на край земли, хоть за край」(哪怕越過邊界)\n跟隨「吉普賽遊牧之星」象徵永無止境", "3.4情感強度等級": "行動後果中度（離開流浪）＋永恆性＋直接吶喊\n情感積極奔放，無哭泣或詛咒"}, "lyrics": "Мохнатый шмель на душистый хмель\nЦапля серая в камыши\nА цыганская дочь за любимым в ночь\nПо родству бродяжьей души\n毛茸茸的蜜蜂飛向芳香的啤酒花\n灰鶴隱匿在蘆葦叢中\n吉普賽女兒為心愛的人在夜晚前行\n遵循著她血脈中的漂泊靈魂。\nТак вперёд, за цыганской звездой кочевой\nНа закат, где дрожат паруса\nИ глаза глядят с бесприютной тоской\nВ багровеющие небеса!\n向前！ 跟隨吉普賽遊牧之星\n直至落日，風帆顫抖的地方\n雙眼中滿是無家可歸的哀愁\n望著血紅的天空！\nИ вдвоём по тропе навстречу судьбе\nНе гадая, в ад или в рай\nТак и надо идти, не страшась пути\nХоть на край земли, хоть за край\n兩人共同踏上小徑，面對命運\n不需猜測是通向地獄還是天堂\n就應當這樣前行，不懼怕路途\n哪怕到地球的盡頭，哪怕越過邊界\nТак вперёд, за цыганской звездой кочевой\nНа свиданье с зарей, на восток\nГде, тиха и нежна, розовеет волна\nНа рассветный вползая песок!\n向前！ 跟隨吉普賽遊牧之星\n赴與黎明之約，前往東方\n在那裡，靜谧而溫柔的波浪，已經染上粉色\n奮力爬上黎明的沙灘！\nТак вперёд, за цыганской звездой кочевой\nДо ревущих южных широт\nГде свирепая буря, как божья метла\nОкеанскую пыль метёт!\n向前！ 跟隨吉普賽遊牧之星\n直至咆哮的南緯地區\n在那裡，狂暴的暴風，如同上帝的掃帚\n沖走了海洋的塵埃！"}, {"id": 2, "batch": 1, "sheet": "範例2 Две гитары 牆後的兩把吉他", "full_title": "範例2 Две гитары 牆後的兩把吉他", "title_ru": "Две гитары", "title_zh": "牆後的兩把吉他", "motif": "思念與痛苦", "analysis": {"1.1情感關鍵詞": {"指標": "思念類、痛苦類詞彙", "分類": "▪ 思念類詞彙\n▪ 痛苦類詞彙"}, "1.2行動關鍵詞": {"指標": "訴說/祈求（向吉他傾訴、請求演奏）", "分類": "▪ 哭泣／祈求\n▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "物品意象（吉他）為主，自然意象次之", "分類": "▪ 物品意象\n▪ 自然意象"}, "2.1敘事視角": {"指標": "第一人稱（自我傾訴）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對大自然/物品（七弦琴）", "分類": "▪ 對大自然／物品"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（思念、失落）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "悲劇結局（永遠分離，無法相見）", "分類": "▪ 悲劇結局（死亡／永遠分離）"}, "3.1情感表現方式": {"指標": "敘述性表達＋沉默/留白（轉向吉他傾訴）", "分類": "▪ 敘述性表達\n▪ 沉默／留白"}, "3.2行動後果": {"指標": "內斂（思念/等待/祈求繼續演奏）", "分類": "▪ 內斂：思念／沉默／等待"}, "3.3時間維度": {"指標": "持續性＋永恆性", "分類": "▪ 持續性（一段時間）\n▪ 永恆性（永遠／一生）"}, "3.4情感強度等級": {"指標": "中度（深沉內斂，非爆發性）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「тоской」(悲傷/思念)\n「мучусь」(痛苦)、「сетую」(哀怨)\n「тоскую」(思念渴望)", "1.2行動關鍵詞": "「Поговори хоть ты со мной」(至少你來與我交談)\n「пой же мне, договори」(為我演奏，繼續演奏)", "1.3意象關鍵詞": "物品：「две гитары」(兩把吉他)、「семиструнная」(七弦琴)——吉普賽音樂象徵\n自然：「звезда」(星星)獨燃——孤獨；「лунная ночь」(月夜)", "2.1敘事視角": "「Душа полна такой тоской」(我的靈魂如此悲傷)\n「Вся жизнь моя прикована」(我整個生命被束縛)", "2.2傾訴對象": "「Поговори хоть ты со мной, Подруга семиструнная」\n(至少你來與我交談，我的七弦琴朋友)\n以吉他代替真實的傾訴對象", "2.3情節發展": "全曲無具體事件\n圍繞「思念已屬於他人的愛人」反覆嘆息", "2.4結局類型": "「Да, ты другому отдана, Без возврата, без возврата」\n(是的，妳已屬於他人，再無回轉)\n反覆的「без возврата」強調無可挽回", "3.1情感表現方式": "「Вся жизнь моя прикована」——敘述式表達\n無法對愛人直說，轉向七弦琴傾訴，形成情感留白", "3.2行動後果": "「тоскую, мучусь, сетую」——只是感受而無外在行動\n以請求吉他繼續演奏為唯一行動", "3.3時間維度": "「И от зари и до зари」(從黎明到黃昏)——持續\n「Вся жизнь моя прикована」(整個生命被束縛)——永恆", "3.4情感強度等級": "行動後果內斂＋持續性至永恆\n情感深沉但以溫柔傾訴形式呈現"}, "lyrics": "Поговори хоть ты со мной,\nПодруга семиструнная…\nДуша полна такой тоской,\nА ночь такая лунная.\n至少你來與我交談吧，\n我的七弦琴朋友…\n我的靈魂是如此悲傷，\n而夜晚如此皎潔明朗。\nВон там звезда одна горит\nТак ярко и мучительно;\nЛучами сердце шевелит,\nДразня его язвительно.\n那裡有一顆星在燃燒\n如此明亮而令人痛苦;\n它的光芒撩動著心弦，\n諷刺地挑釁著。\nЧего от сердца нужно ей,\nВедь знает без того она\n她想從心中得到什麼，\n其實她早已知道\nЧто к ней тоскою долгих лет\nВся жизнь моя прикована.\n我整個生命都被\n漫長歲月裡對她的思念所束縛。\nБасан, басан, басана,\nБасана да басана…\nДа, ты другому отдана\nБез возврата, без возврата.\n巴桑，巴桑，巴桑納，\n巴桑納，巴桑納…\n是的，妳已屬於他人\n再無回轉，再無回轉。\nИ от зари и до зари\nТоскую, мучусь, сетую…\nТак пой же мне, договори\nТу песню недопетую.\n從黎明到黃昏\n我渴望、痛苦、哀怨著…\n那就為我演奏吧，繼續演奏\n那首未完的歌。\nДве гитары, зазвенев,\nЖалобно заныли,\nС детства памятный напев:\nДруг любимый, ты ли ?…\n兩把吉他，響起聲音，\n悲傷地呻吟，\n唱出童年時令人難忘的旋律：\n心愛的朋友，是你嗎？ …\nЭх раз, ещё раз,\nЕщё много-много раз.\nЭх раз, ещё раз,\nЕщё много-много раз.\n哎，再來一次，\n再來一次，還要很多很多次。\n哎，再來一次，\n再來一次，還要很多很多次。"}, {"id": 3, "batch": 1, "sheet": "範例3 Дорогой длинною 漫長的道路", "full_title": "範例3 Дорогой длинною 漫長的道路", "title_ru": "Дорогой длинною", "title_zh": "漫長的道路", "motif": "思念與痛苦", "analysis": {"1.1情感關鍵詞": {"指標": "思念類、痛苦類（帶回憶色彩）", "分類": "▪ 思念類詞彙\n▪ 痛苦類詞彙"}, "1.2行動關鍵詞": {"指標": "出發、歌唱、告別", "分類": "▪ 離開／留下\n▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "物品意象（三駕馬車、七弦琴）＋自然意象（月夜、燈光）", "分類": "▪ 物品意象\n▪ 自然意象"}, "2.1敘事視角": {"指標": "第一人稱（我/我們，回憶視角）", "分類": "▪ 第一人稱（我）\n▪ 混合視角"}, "2.2傾訴對象": {"指標": "對自己/對聽眾（回憶性嘆息）", "分類": "▪ 對自己\n▪ 對聽眾"}, "2.3情節發展": {"指標": "有明確情節轉折（昔日歡樂→告別過去→新路出發）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "和解結局（放下過去，接受命運）", "分類": "▪ 和解結局（放下／祝福）"}, "3.1情感表現方式": {"指標": "隱喻/暗示＋敘述性表達", "分類": "▪ 隱喻／暗示\n▪ 敘述性表達"}, "3.2行動後果": {"指標": "內斂（平靜告別，接受過去已逝）", "分類": "▪ 內斂：思念／沉默／等待"}, "3.3時間維度": {"指標": "持續性＋永恆性（回憶中的整夜折磨）", "分類": "▪ 持續性（一段時間）\n▪ 永恆性（永遠／一生）"}, "3.4情感強度等級": {"指標": "內斂（以距離感淡化痛苦）", "分類": "▪ 內斂"}}, "evidence": {"1.1情感關鍵詞": "「тоски」(憂愁/思念)、「мучила」(折磨)\n「задаром」(徒然/枉然)暗示惋惜", "1.2行動關鍵詞": "「ехали」(乘坐出發)、「пели」(歌唱)\n「покончили со старым」(與過去告別)", "1.3意象關鍵詞": "物品：「тройка с бубенцами」(三駕馬車鈴聲)、「семиструнная」(七弦琴)、「дорога」(道路)——人生旅程\n自然：「огоньки」(遠處燈光)、「лунная погода」(月夜)", "2.1敘事視角": "「Эх, когда бы мне теперь за вами」(要是我能跟隨你們)\n「Да, выходит, пели мы задаром」(我們徒然歌唱)", "2.2傾訴對象": "無直接呼告對象\n以第一人稱嘆息貫穿，具向聽眾分享回憶的性質", "2.3情節發展": "過去：乘三駕馬車，鈴聲輕快\n轉折：「Если мы покончили со старым」(既然已與過去告別)\n現在：「В даль родную новыми путями нам ехать суждено!」", "2.4結局類型": "「Значит ночи эти отошли!」(這些夜晚已遠去)\n「Да теперь проехали давно!」(如今早已過去)\n平靜告別舊日，是釋懷而非悲傷", "3.1情感表現方式": "七弦琴「整夜折磨我」=以樂器比喻愛情痛苦\n「漫長的道路、月夜、遠去的歌聲」=人生旅程比喻\n回憶的敘述語氣淡化情感強度", "3.2行動後果": "「Значит ночи эти отошли!」——非哭泣或詛咒，是平靜的自我說服\n「Да теперь проехали давно!」以嘆氣式語氣收尾", "3.3時間維度": "「По ночам так мучила меня」(整夜整夜折磨我)——持續\n七弦琴貫穿整段人生——永恆視角", "3.4情感強度等級": "情感已與過去告別\n以回憶的距離感淡化，七弦琴的折磨停留在過去\n「行動後果內斂」＋「和解結局」"}, "lyrics": "Ехали на тройке с бубенцами,\nА вдали мелькали огоньки…\nЭх, когда бы мне теперь за вами,\nДушу бы развеять от тоски!\n我們乘坐著三駕馬車，伴隨鈴聲輕快響起\n遠處閃爍著燈光\n哦，要是現在能跟隨你們，\n就能讓靈魂從憂愁中驅散！\nДорогой длинною,\nПогодой лунною,\nДа с песней той,\nЧто вдаль летит звеня,\nДа с той старинною,\nДа с семиструнною,\nЧто по ночам\nТак мучила меня.\n在漫長的道路上，\n在明月如水的夜晚，\n伴隨著那首歌，\n它輕鳴著遠去，\n伴隨著那古老的\n七弦的旋律，\n整夜整夜地\n不斷折磨著我。\nПо ночам 的по不是地點意義(沿著)，而是時間意義(每個夜晚)\nДорогой длинною,\nПогодой лунною,\nДа с песней той,\nЧто вдаль летит звеня,\nДа с той старинною,\nДа с семиструнною,\nЧто по ночам\nТак мучила меня.\n在漫長的道路上，\n在明月如水的夜晚，\n伴隨著那首歌，\n它輕鳴著遠去，\n伴隨著那古老的\n七弦的旋律，\n整夜整夜地\n不斷折磨著我。\nДа, выходит, пели мы задаром,\nПонапрасну ночь за ночью жгли.\nЕсли мы покончили со старым,\nЗначит ночи эти отошли!\n是的，我們徒然歌唱，\n營火一夜又一夜徒勞無功的燃燒\n既然我們已與過去告別，\n那麼這些夜晚就已遠去！\nДорогой длинною,\nПогодой лунною,\nДа с песней той,\nЧто вдаль летит звеня,\nДа с той старинною,\nДа с семиструнною,\nЧто по ночам\nТак мучила меня.\n在漫長的道路上，\n在明月如水的夜晚，\n伴隨著那首歌，\n它輕鳴著遠去，\n伴隨著那古老的\n七弦的旋律，\n整夜整夜地\n不斷折磨著我。\nЛа-лай-лай-лай-ла-ла…\nВ даль родную новыми путями\nНам отныне ехать суждено!\nЕхали на тройке с бубенцами,\nДа теперь проехали давно!\n沿著新的道路前往遙遠故土，\n這是我們命中注定要去之處!\n曾經乘坐著三駕馬車，伴隨鈴聲輕快響起\n如今早已過去！\nДорогой длинною,\nПогодой лунною,\nДа с песней той,\nЧто вдаль летит звеня,\nДа с той старинною,\nДа с семиструнною,\nЧто по ночам\nТак мучила меня.\n在漫長的道路上，\n在明月如水的夜晚，\n伴隨著那首歌，\n它輕鳴著遠去，\n伴隨著那古老的\n七弦的旋律，\n整夜整夜地\n不斷折磨著我。\nДорогой длинною,\nПогодой лунною,\nДа с песней той,\nЧто вдаль летит звеня,\nДа с той старинною,\nДа с семиструнною,\nЧто по ночам\nТак мучила меня\n在漫長的道路上，\n在明月如水的夜晚，\n伴隨著那首歌，\n它輕鳴著遠去，\n伴隨著那古老的\n七弦的旋律，\n整夜整夜地\n不斷折磨著我。"}, {"id": 4, "batch": 1, "sheet": "範例4 Милая 親愛的", "full_title": "範例4 Милая 親愛的", "title_ru": "Милая", "title_zh": "親愛的", "motif": "思念與痛苦", "analysis": {"1.1情感關鍵詞": {"指標": "愛戀類、痛苦類（甘願受苦）", "分類": "▪ 愛戀類詞彙\n▪ 痛苦類詞彙"}, "1.2行動關鍵詞": {"指標": "哭泣/祈求（懇求被看見/被聽見）", "分類": "▪ 哭泣／祈求\n▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "物品意象（吉他）＋自然意象（五月天）＋光芒意象", "分類": "▪ 物品意象\n▪ 自然意象"}, "2.1敘事視角": {"指標": "第一人稱（當下的懇求者）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（直接呼告式）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（停在懇求的當下瞬間）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "開放式結局（懇求是否被聽見仍為未知）", "分類": "▪ 開放式結局（未知）"}, "3.1情感表現方式": {"指標": "直接高昂吶喊（懇求式）＋比喻", "分類": "▪ 直接高昂吶喊／控訴\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "中度（反覆祈求，甘願受苦）", "分類": "▪ 中度：哭泣／祈求"}, "3.3時間維度": {"指標": "當下爆發（固定在窗下這一刻）", "分類": "▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "中度（熱切懇求，非毀滅性）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「Много мук я терпел」(我承受了許多痛苦)\n「страдать был бы рад」(樂意繼續承受)\n「ласковый взгляд」(和藹的眼神)——渴望中帶著愛戀", "1.2行動關鍵詞": "「Милая, ты услышь меня」(親愛的，請聽我說)\n「взгляни ж на меня, Ну, хоть один только раз」(請看我，哪怕只有一次)", "1.3意象關鍵詞": "物品：「с гитарою」(手持吉他)——吉普賽愛的訴說\n自然：「майского дня」(五月天)作比喻基準\n光芒：「Чудный блеск твоих глаз」(眼中美妙光芒)——以光象徵愛慕", "2.1敘事視角": "「Под окном стою, я с гитарою」(我站在窗下，手持吉他)\n全曲以「我」的當下行動為中心", "2.2傾訴對象": "「Милая, ты услышь меня」(親愛的，請聽我說)\n開篇即直接點名，呼告愛人", "2.3情節發展": "全曲停留在「站在窗下等待、懇求被看見」的單一場景\n無過去回憶或未來想像", "2.4結局類型": "結尾回到「Милая, ты услышь меня, Под окном стою, я с гитарою」\n循環式收尾，等待是否被回應仍未知", "3.1情感表現方式": "反覆呼喊「Милая」(親愛的)——直接高昂\n「Ярче майского дня, Чудный блеск твоих глаз」——比喻", "3.2行動後果": "「Ну, хоть один только раз」(哪怕只有一次)——反覆祈求\n「страдать был бы рад」(樂意繼續受苦)——甘願的痛苦", "3.3時間維度": "「Под окном стою」(此刻站在窗下)\n場景固定在當下某一特定時刻", "3.4情感強度等級": "行動後果中度（祈求）＋當下爆發\n情感熱切但非破壞性，以甘願受苦表現深情"}, "lyrics": "Милая, ты услышь меня,\nПод окном стою, я с гитарою.\n親愛的，請聽我說，\n我站在窗下，手持吉他。\nТак взгляни ж на меня,\nНу, хоть один только раз,\nЯрче майского дня,\nЧудный блеск твоих глаз.\n請看看我，\n哪怕只有一次，\n妳眼中閃耀的美妙光芒\n比五月的晴天更加明亮\nМного мук я терпел,\nИ страдать был бы рад,\nЕсли б душу согрел,\nМне твой ласковый взгляд.\n我承受了許多痛苦，\n我樂意繼續承受，\n只要妳和藹的眼神\n就能溫暖我的靈魂\nТак взгляни ж на меня,\nНу, хоть один только раз,\nЯрче майского дня,\nЧудный блеск твоих глаз.\n請看看我，\n哪怕只有一次，\n妳眼中閃耀的美妙光芒\n比五月的晴天更加明亮\nМилая, ты услышь меня,\nПод окном стою, я с гитарою\n親愛的，請聽我說，\n我站在窗下，手持吉他。"}, {"id": 5, "batch": 1, "sheet": "範例5 Очи черные 黑眼睛", "full_title": "範例5 Очи черные 黑眼睛", "title_ru": "Очи черные", "title_zh": "黑眼睛", "motif": "背叛", "analysis": {"1.1情感關鍵詞": {"指標": "愛戀類、痛苦類、沉淪類（矛盾並存）", "分類": "▪ 愛戀類詞彙\n▪ 痛苦類詞彙\n▪ 沉淪類詞彙"}, "1.2行動關鍵詞": {"指標": "詛咒、獻祭（強烈的情感行動）", "分類": "▪ 詛咒／祝福\n▪ 殺人／報復"}, "1.3意象關鍵詞": {"指標": "顏色意象（黑眼睛）為核心，自然意象（夜/夢）＋物品意象", "分類": "▪ 顏色意象\n▪ 自然意象\n▪ 物品意象"}, "2.1敘事視角": {"指標": "第一人稱（主動告白與控訴）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（尊稱вы直接呼告黑眼睛）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "有明確情節轉折（相遇→沉淪→詛咒→獻祭式和解）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "悲劇結局＋部分和解（矛盾收尾）", "分類": "▪ 悲劇結局（永遠分離）\n▪ 和解結局（放下）"}, "3.1情感表現方式": {"指標": "直接高昂吶喊/控訴（全曲最高強度）", "分類": "▪ 直接高昂吶喊／控訴"}, "3.2行動後果": {"指標": "強烈（詛咒＋自我毀滅式獻祭）", "分類": "▪ 強烈：詛咒／仇恨"}, "3.3時間維度": {"指標": "永恆性（幸福永遠失去）", "分類": "▪ 永恆性（永遠／一生）"}, "3.4情感強度等級": {"指標": "強烈", "分類": "▪ 強烈"}}, "evidence": {"1.1情感關鍵詞": "「Как люблю я вас!」(我多麼愛您)\n「Как боюсь я вас!」(我又多麼畏懼您)\n「страдал」(受苦)、「счастие」(幸福)——愛與毀滅並存", "1.2行動關鍵詞": "「Вы сгубили меня」(您毀了我)\n「Будь тот проклят час」(詛咒那個時刻)\n「В жертву отдал я огненным глазам」(將一切獻祭給炙熱的眼睛)", "1.3意象關鍵詞": "顏色：「Очи чёрные」(黑眼睛)——神秘、誘惑、致命\n自然：「полуночном сне」(午夜夢中)、「ночь темна」(漆黑夜晚)\n物品：「шампанское」(香檳)——騎兵的祭酒", "2.1敘事視角": "「Как люблю я вас!」、「Я бы прожил жизнь улыбаюсь」\n「В жертву отдал я」——全程以「我」為主語", "2.2傾訴對象": "「Очи чёрные, очи страстные!」——直接呼告黑眼睛代指愛人\n注：原文以「вы」(尊稱您)而非「ты」，表現仰視崇拜的心理", "2.3情節發展": "相遇：「увидел вас я в недобрый час」(在不幸時刻遇見您)\n沉淪：「Вы сгубили меня」(您毀了我)\n詛咒：「Будь тот проклят час」\n和解：「Но не грустен я...В жертву отдал я」", "2.4結局類型": "「Унесли навек моё счастие」(永遠帶走幸福)——悲劇\n「Но не грустен я, не печален я」——矛盾式的自我和解", "3.1情感表現方式": "「Очи чёрные, очи страстные!」高昂直呼\n「Вы сгубили меня！」直接控訴\n「Будь тот проклят час!」強烈詛咒", "3.2行動後果": "「Будь тот проклят час, когда встретил вас」(詛咒遇見您的時刻)\n「В жертву отдал я огненным глазам」(將一切獻祭給炙熱眼睛)\n詛咒＋自我毀滅=強烈行動後果", "3.3時間維度": "「Унесли навек моё счастие」(永遠帶走了我的幸福)\n「навек」(永遠)直接點明", "3.4情感強度等級": "「行動後果強烈（詛咒＋獻祭）」＋「永恆性」\n愛與毀滅並存，自我矛盾達到情感頂峰"}, "lyrics": "Очи чёрные, очи страстные!\nОчи жгучие и прекрасные!\nКак люблю я вас! Как боюсь я вас!\nЗнать, увидел вас я в недобрый час!\n黑色的眼睛，熱情的眼睛！\n熾熱而美麗的眼睛！\n我多麼愛您！ 我又多麼畏懼您！\n我知道，我在不幸的時刻遇見了您！\n(這裡的вы不是複數，而是尊敬的您，表示男主對女主的尊敬：女生高高在上，男生俯臥在地仰視女生的感覺，哈!!)\nНе встречал бы вас, не страдал бы так,\nЯ бы прожил жизнь улыбаюсь.\nВы сгубили меня, очи чёрные,\nУнесли навек моё счастие.\n如果不曾遇見您，就不會如此受苦，\n我本可以帶著微笑度過生活\n是您毀了我，黑色的眼睛，\n永遠帶走了我的幸福。\nНо не грустен я, не печален я,\nУтешительна мне судьба моя.\nВсё, что лучшего в жизни Бог дал нам\nВ жертву отдал я огненным глазам.\n但我並不悲傷，也不沮喪，\n我的命運慰藉了我\n上帝賦予生命中最美好的一切，\n我都獻祭給了這雙炙熱的眼睛。\nВсе гусары спят беспробудным сном.\nЛишь один не спит, пьет шампанское\nЗа любовь свою, за цыганскую.\n所有的騎兵都沉睡在深不可醒的夢中。\n只有一個人未睡，他正在飲用香檳\n為了他的愛情，對吉普賽女人之愛。\nОчи черные, очи страстные,\nОчи жгучие и прекрасные,\nКак люблю я вас, как боюсь я вас,\nЗнать, увидел вас я в недобрый час.\nЗнать, увидел вас я в недобрый час.\n黑色的眼睛，熱情的眼睛！\n熾熱而美麗的眼睛！\n我多麼愛您！ 我又多麼畏懼您！\n我知道，我在不幸的時刻遇見了您！\nНе встречал бы вас - не страдал бы так,\nВек свой прожил бы припеваючи.\nВы сгубили меня, очи чёрные,\nУнесли навек моё счастие.\n如果不曾遇見您，就不會如此受苦，\n我本可以帶著微笑度過生活\n是您毀了我，黑色的眼睛，\n永遠帶走了我的幸福。\nБудь тот проклят час, когда встретил вас,\nОчи чёрные, непокорные!\nНе видал бы вас, не страдал бы так,\nЯ бы прожил жизнь припеваючи.\n詛咒那個遇見您的時刻，\n黑色的、不馴服的眼睛！\n如果不曾看到您，就不會如此痛苦，\n我本可以歡樂地活著。\nЧасто снится мне в полуночном сне\nИ мерещится счастье близкое,\nА проснулся я - ночь кругом темна,\nИ здесь некому пожалеть меня.\n在午夜中我經常作夢\n那近在咫尺的幸福，\n但醒來時 - 四週一片漆黑，\n這裡無人可憐我。"}, {"id": 6, "batch": 1, "sheet": "範例6 Твои глаза зеленые 你那綠色的眼睛", "full_title": "範例6 Твои глаза зеленые 你那綠色的眼睛", "title_ru": "Твои глаза зеленые", "title_zh": "你那綠色的眼睛", "motif": "義務與激情", "analysis": {"1.1情感關鍵詞": {"指標": "愛戀類、沉淪類（迷亂失控）", "分類": "▪ 愛戀類詞彙\n▪ 沉淪類詞彙"}, "1.2行動關鍵詞": {"指標": "無法回頭、被命運連結（被動行動）", "分類": "▪ 離開／留下\n▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "顏色意象（綠眼睛）為核心＋自然意象（漩渦、河流）＋物品意象", "分類": "▪ 顏色意象\n▪ 自然意象\n▪ 物品意象"}, "2.1敘事視角": {"指標": "第一人稱（沉浸式，迷亂狀態）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（ты，二人稱，直接呼告）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（沉醉的當下感受）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "開放式偏悲劇（平靜無法重返，隱含放棄暗示）", "分類": "▪ 開放式結局（未知）\n▪ 悲劇結局"}, "3.1情感表現方式": {"指標": "隱喻/暗示為主（詩意意象隱喻）", "分類": "▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "中度偏強（失去理智、平靜永遠失去）", "分類": "▪ 中度：生病\n▪ 強烈：仇恨／永不相見"}, "3.3時間維度": {"指標": "當下爆發（今天）＋持續性（仍在迴響）", "分類": "▪ 當下爆發（此時此刻）\n▪ 持續性（一段時間）"}, "3.4情感強度等級": {"指標": "中度偏強（沉淪感強烈但以詩意隱喻呈現）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「Свели меня с ума」(讓我瘋狂)\n「кружится голова」(頭暈目眩)\n「любовь нельзя понять」(愛是無法理解的)", "1.2行動關鍵詞": "「Связала нас сама」(將我們連結在一起)——被動語態，命運的控制\n「Покоя больше не вернуть」(平靜無法重返)", "1.3意象關鍵詞": "顏色：「глаза зеленые」(綠眼睛)——誘惑、深不可測\n自然：「омуте речном」(河流漩渦)——沉淪的比喻；「речную глубину」(河流深處)——暗示沉淪到底\n物品：「нитью тонкою」(細線)——脆弱卻難斷的連結；「запертые ставни」(緊閉百葉窗)", "2.1敘事視角": "「Свели меня с ума」\n「кружится голова」(我的頭暈眩)\n「Покоя все равно мне больше не вернуть」(我的平靜再無法重返)", "2.2傾訴對象": "「Твои глаза зеленые」(你那綠色的眼睛)\n「Твои слова обманные」(你那虛假的話語)\n用「твои」(你的)直接指向愛人", "2.3情節發展": "全曲沉浸在迷亂沉醉的當下感受\n「Сегодня нитью тонкою Связала нас сама」——無起點無終點的存在狀態", "2.4結局類型": "「Покоя все равно мне больше не вернуть」(平靜無法重返)\n「В речную глубину без страха заглянуть」(無畏凝視河流深處)——隱含近乎沉淪到底的意志", "3.1情感表現方式": "「омут речной」(河流漩渦)——愛情深淵的比喻\n「нитью тонкою」(細線)——脆弱卻難斷的連結\n「речную глубину без страха заглянуть」——隱含沉淪到底的意志", "3.2行動後果": "「Свели меня с ума」(讓我瘋狂)——失去理智\n「Покоя больше не вернуть」(平靜無法重返)\n以隱喻方式呈現，非直接行動", "3.3時間維度": "「Сегодня нитью тонкою Связала нас сама」(今天)\n「В ушах еще звучит наш разговор недавний」(耳邊仍迴響著近期的對話)", "3.4情感強度等級": "隱喻表達＋失去理智後果＋當下爆發\n非直接控訴，但「河流深處」意象暗示情感已接近邊緣"}, "lyrics": "Так хочется хоть раз, в последний раз поверить,\nНе все ли мне равно, что сбудется потом;\nЛюбви нельзя понять, любовь нельзя измерить,\nВедь там, на дне души, как в омуте речном.\n多麼渴望至少一次，最後一次相信，\n無所謂之後會發生什麼;\n愛是無法理解的，愛是無法衡量的，\n因為在那裡，在心裡的深處，就像位在河流的漩渦中\nэта глубь бездонная,\nПусть эта даль туманная\nСегодня нитью тонкою\nСвязала нас сама,\nТвои глаза зеленые,\nТвои слова обманные\nИ эта песня звонкая\nСвели меня с ума.\n今天用細細的線\n讓這無底的深淵，\n讓這煙霧繚繞的遠方\n與我們連結在一起\n你那綠色的眼眸，\n你那虛假的話語\n還有這悅耳的歌聲\n已讓我瘋狂。\nПроглянет солнца луч сквозь запертые ставни,\nА все еще слегка кружится голова,\nВ ушах еще звучит наш разговор недавний,\nКак струнный перебор, звучат твои слова.\n一縷陽光穿過了緊閉的百葉窗\n而我的頭仍然微微的暈眩\n耳邊仍迴響著我們近期的對話，\n如同琴弦的輕撥，你的話語依然縈繞。\nПусть эта глубь бездонная,\nПусть эта даль туманная\nСегодня нитью тонкою\nСвязала нас сама,\nТвои глаза зеленые,\nТвои слова обманные\nИ эта песня звонкая\nСвели меня с ума.\n今天用細細的線\n讓這無底的深淵，\n讓這煙霧繚繞的遠方\n與我們連結在一起\n你那綠色的眼眸，\n你那虛假的話語\n還有這悅耳的歌聲\n已讓我瘋狂。\nНе нужно ничего, ни поздних сожалений,\nПокоя все равно мне больше не вернуть.\nТак хочется хоть раз на несколько мгновений\nВ речную глубину без страха заглянуть.\n不再需要任何東西，不再有晚來的遺憾，\n無論如何平靜已無法重返。\n多麼渴望至少幾個瞬間\n無所畏懼地凝視河流的深處。\nПусть эта глубь бездонная,\nПусть эта даль туманная\nСегодня нитью тонкою\nСвязала нас сама,\nТвои глаза зеленые,\nТвои слова обманные\nИ эта песня звонкая\nСвели меня с ума.\n今天用細細的線\n讓這無底的深淵，\n讓這煙霧繚繞的遠方\n與我們連結在一起\n你那綠色的眼眸，\n你那虛假的話語\n還有這悅耳的歌聲\n已讓我瘋狂。"}, {"id": 7, "batch": 1, "sheet": "範例7 Глаза 眼睛", "full_title": "範例7 Глаза 眼睛", "title_ru": "Глаза", "title_zh": "眼睛", "motif": "義務與激情", "analysis": {"1.1情感關鍵詞": {"指標": "愛戀類（含蓄的期待與暗示）", "分類": "▪ 愛戀類詞彙"}, "1.2行動關鍵詞": {"指標": "等待、相遇、保守秘密", "分類": "▪ 離開／留下\n▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "自然意象（麥田/黑夜）為核心，顏色意象次之", "分類": "▪ 自然意象\n▪ 顏色意象\n▪ 物品意象"}, "2.1敘事視角": {"指標": "第三人稱（旁觀者敘事視角）", "分類": "▪ 第三人稱（他／她）"}, "2.2傾訴對象": {"指標": "對大自然/物品（呼告麥田保守秘密）＋對聽眾（敘事性）", "分類": "▪ 對大自然／物品\n▪ 對聽眾"}, "2.3情節發展": {"指標": "有明確情節轉折（貨郎到來→等待黑眼睛姑娘→夜晚相好→請求秘密）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "開放式偏和解（秘密被保守，暗含美好）", "分類": "▪ 開放式結局（未知）\n▪ 和解結局（放下／祝福）"}, "3.1情感表現方式": {"指標": "敘述性表達＋象徵隱喻（以自然意象包裹愛情）", "分類": "▪ 敘述性表達\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "內斂（等待、相遇、秘密相好）", "分類": "▪ 內斂：思念／沉默／等待"}, "3.3時間維度": {"指標": "當下爆發（某一特定夜晚的相遇）", "分類": "▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "內斂（最輕盈，唯一以喜悅基調為主的曲目）", "分類": "▪ 內斂"}}, "evidence": {"1.1情感關鍵詞": "「зазнобушка」(心上人/心肝寶貝)\n「черноокую」(那黑眼睛的姑娘)\n情感以間接稱呼與等待呈現，非直白宣告", "1.2行動關鍵詞": "「подожду」(我會等待)\n「разложу товары」(攤開所有商品——以行動表達愛意)\n「тайну свято сохрани!」(請保守這個神聖的秘密)", "1.3意象關鍵詞": "自然：「рожь высокая」(高高的麥田)——愛情相遇的隱密空間；「ночка тёмная」(黑夜)——見證秘密\n顏色：「черноокую」(黑眼睛)——神秘誘惑\n物品：「коробушка」(小貨箱)——青年用以打動心上人的媒介", "2.1敘事視角": "全曲由旁觀者講述貨郎的故事\n「Коробейники идут」(貨郎們來了)\n「Как поладили они」(關於他們如何相好)——旁觀者口吻", "2.2傾訴對象": "「Распрямись ты, рожь высокая, Тайну свято сохрани!」\n(高高的麥子，請保守這個神聖的秘密！)\n末段轉向麥田直接呼告，為全曲最具情感的一句", "2.3情節發展": "貨郎挑擔而來→聽見年輕腳步聲→等到夜晚相遇→「只有黑夜知道他們如何相好」\n完整的相遇敘事弧，情節最為完整", "2.4結局類型": "「Тайну свято сохрани!」(請保守這個神聖的秘密)\n結局開放但語氣輕盈美好，非悲傷收尾", "3.1情感表現方式": "以第三人稱敘事距離呈現\n麥田=愛情隱密空間、黑夜=見證者\n貨郎「攤開商品」實為向心上人表達誠意的象徵行為", "3.2行動後果": "「подожду」(等待)是全曲最強的行動\n結果以「秘密」包裹，無悲劇後果\n六首中唯一以輕盈愉悅情感收尾的曲目", "3.3時間維度": "「А завижу черноокую — Все товары разложу」(一旦看見黑眼睛的姑娘——攤開所有商品)\n事件集中在那一個夜晚", "3.4情感強度等級": "行動後果內斂（等待/相遇）＋當下爆發\n敘事視角保持旁觀距離\n全曲無悲傷、無詛咒、無失落"}, "lyrics": "Не тростник во ржи колышется -\n在麥田裡搖曳的不是蘆葦，\nНе дубравушка шумит -\n沙沙作響的不是小橡樹林，\nМолодецкая поступь слышится -\n聽見的是年輕小夥子的腳步聲，\nКоробейники идут -\n貨郎們來了。\nЭх, полна, полна коробушка -\n唉呀，滿滿的，滿滿的小貨箱，\nЕсть и ситец, и парча -\n既有棉布，也有錦緞。\nПожалей, душа-зазнобушка -\n親愛的心上人啊，請可憐可憐\nМолодецкого плеча -\n我這個年輕的肩膀。\nВыйди, выйди в рожь высокую -\n出來吧，出來到高高的麥田裡，\nТам до ночки подожду -\n我會在那裡等到夜晚。\nА завижу черноокую -\n一旦我看見那黑眼睛的姑娘，\nВсе товары разложу -\n我會攤開所有的商品。\nПро то знала ночка тёмная -\n只有黑夜知曉這件事，\nКак поладили они -\n關於他們如何相好，\nРаспрямись ты, рожь высокая -\n高高的麥子，挺直腰桿吧，\nТайну свято сохрани! -\n請保守這個神聖的秘密！"}, {"id": 8, "batch": 1, "sheet": "範例8 秋天的風哀傷地呻吟著", "full_title": "範例8 Жалобно стонет ветер осенний 秋天的風哀傷地呻吟著", "title_ru": "Жалобно стонет ветер осенний", "title_zh": "秋天的風哀傷地呻吟著", "motif": "思念與痛苦", "analysis": {"1.1情感關鍵詞": {"指標": "思念類、痛苦類（觸景傷情，幻夢破滅）", "分類": "▪ 思念類詞彙\n▪ 痛苦類詞彙"}, "1.2行動關鍵詞": {"指標": "沉默/等待（回憶，無外在行動）", "分類": "▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "自然意象（秋風/落葉）為絕對核心，顏色意象次之", "分類": "▪ 自然意象\n▪ 顏色意象"}, "2.1敘事視角": {"指標": "第一人稱（回憶者的內省視角）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對自己（內省式回憶，無直接呼告對象）", "分類": "▪ 對自己"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（秋景觸發的回憶流動）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "悲劇結局（一切都是幻夢，幸福已逝）", "分類": "▪ 悲劇結局（死亡／永遠分離）"}, "3.1情感表現方式": {"指標": "隱喻/暗示（秋景=愁緒）＋敘述性表達", "分類": "▪ 隱喻／暗示\n▪ 敘述性表達"}, "3.2行動後果": {"指標": "內斂（思念/沉默/對記憶的承受）", "分類": "▪ 內斂：思念／沉默／等待"}, "3.3時間維度": {"指標": "持續性（回憶與現在秋景的交織往復）", "分類": "▪ 持續性（一段時間）"}, "3.4情感強度等級": {"指標": "內斂（最靜默的哀愁，以秋景包裹一切）", "分類": "▪ 內斂"}}, "evidence": {"1.1情感關鍵詞": "「томления」(憂鬱的情感)\n「счастье утекшее」(已逝去的幸福)\n「бередит」(刺痛靈魂)\n「грезы одне」(都只是一場幻夢)", "1.2行動關鍵詞": "「помнится」(回憶起)、「помнятся」(記得)\n全曲無任何外在行動，只有「記起→刺痛」的內心流動", "1.3意象關鍵詞": "自然：「ветер осенний」(秋風)——哀愁象徵；「листья кружатся поблекшие」(枯萎的樹葉盤旋)\n秋景作為全曲情感的外在對應，風敲打窗戶=記憶侵擾內心\n顏色：「очи лазурные」(湛藍的眼睛)、「рученьки белые」(白皙的小手)——回憶中愛人的美麗", "2.1敘事視角": "「любил беззаветно я」(我無悔地愛過)\n「Душу мою бередит」(刺痛著我的靈魂)\n整體以「我」的回憶與感受為中心", "2.2傾訴對象": "全曲無直接呼告愛人或聽眾\n完全是自我內心的回憶與感嘆\n最為封閉的情感結構", "2.3情節發展": "現在：秋風/落葉的蕭瑟\n回憶：夏夜的歡笑、溫柔的眼睛與雙手\n當下：「都只是一場幻夢」\n是情緒的對比流動，非事件的情節發展", "2.4結局類型": "「Были лишь грезы одне」(都只是一場幻夢)\n「Память о тех счастливых мгновениях, Душу мою бередит」(記憶刺痛靈魂)\n沒有和解，只有反覆的刺痛", "3.1情感表現方式": "「Жалобно стонет ветер осенний」(秋風哀傷地呻吟)——以自然意象映射內心\n「Ветер в окошко стучит」(風敲打窗戶)——記憶的叩問\n敘述性地陳述幸福已逝，無高昂吶喊", "3.2行動後果": "「Душу мою бередит」(刺痛靈魂)——被動承受，非主動行動\n全曲無任何對外的行為，只有內心被刺痛", "3.3時間維度": "秋天的景象持續觸發回憶\n「Медленно кружатся листья осенние」(秋葉緩緩盤旋)暗示這份憂鬱持續存在\n非單一爆發時刻", "3.4情感強度等級": "行動後果內斂＋持續性＋隱喻表達\n情感以自然意象的靜謐方式流洩，不訴諸吶喊或詛咒"}, "lyrics": "Жалобно стонет ветер осенний -\n秋天的風哀傷地呻吟著，\nЛистья кружатся поблекшие -\n枯萎的樹葉盤旋飛舞，\nСердце наполнилось чувством томления -\n心中充滿了憂鬱的情感，\nПомнится счастье утекшее -\n回憶起已逝去的幸福。\nПомнятся летние ночи веселые -\n記得那些夜晚的歡樂\nНежные речи приветные -\n溫柔問候的話語，\nОчи лазурные, рученьки белые -\n湛藍的眼睛，白皙的小手，\nЛаски любви бесконечные -\n無盡愛意的撫慰。\nВсе, что бывало, любил беззаветно я -\n曾經的一切，我無悔地愛過，\nВсе, во что верилось мне -\n所有我曾相信的一切，\nВсе эти ласки и речи приветные -\n所有這些愛撫和問候的話語\nБыли лишь грезы одне -\n都只是一場幻夢！\nМедленно кружатся листья осенние -\n秋天的樹葉緩緩盤旋，\nВетер в окошко стучит… -\n風兒敲打著窗戶…\nПамять о тех счастливых мгновениях -\n那些幸福瞬間的記憶\nДушу мою бередит -\n刺痛著我的靈魂。"}, {"id": 9, "batch": 1, "sheet": "範例9 Люли 柳莉", "full_title": "範例9 Люли 柳莉", "title_ru": "Люли", "title_zh": "柳莉", "motif": "忌妒", "analysis": {"1.1情感關鍵詞": {"指標": "忌妒類（男方）＋驕傲/輕蔑類（女方拒絕）", "分類": "▪ 忌妒類詞彙"}, "1.2行動關鍵詞": {"指標": "拒絕（女方的核心行動）", "分類": "▪ 攻擊／收手\n▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "自然意象（暴風雪）＋顏色意象（黑帽/白手）＋物品意象（帽子）", "分類": "▪ 自然意象\n▪ 顏色意象\n▪ 物品意象"}, "2.1敘事視角": {"指標": "混合視角（第三人稱敘事→女性第一人稱表態）", "分類": "▪ 第三人稱（他／她）\n▪ 混合視角"}, "2.2傾訴對象": {"指標": "對愛人（女方被請求）→轉為女方的主動表態", "分類": "▪ 對愛人\n▪ 對自己"}, "2.3情節發展": {"指標": "有明確情節轉折（青年來→帽子飛落→被請求→女方拒絕）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "開放式（女方拒絕後結局未明）", "分類": "▪ 開放式結局（未知）"}, "3.1情感表現方式": {"指標": "象徵行動（不撿帽子=不低頭）＋敘述性表達", "分類": "▪ 敘述性表達\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "中度（明確拒絕，保持自我尊嚴）", "分類": "▪ 中度：離開"}, "3.3時間維度": {"指標": "當下爆發（特定時刻的對峙場景）", "分類": "▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "中度（以尊嚴的拒絕取代哭泣或詛咒）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「ревнивого」(忌妒的那個人)——男方被定性為忌妒者\n女方以「不會弄髒白手」表達驕傲與拒絕，非常規的情感關鍵詞", "1.2行動關鍵詞": "「Я не буду чёрну шляпу поднимать」(我不會去撿起那頂黑帽)\n「Я не буду белых рук своих марать」(我不會弄髒自己潔白的雙手)\n拒絕低頭=拒絕原諒/回頭，以行動拒絕代替語言", "1.3意象關鍵詞": "自然：「метелица」(暴風雪)——動盪環境，象徵感情的混亂\n顏色：「чёрну шляпу」(黑色帽子)——男方的象徵物件；「белых рук」(白皙的雙手)——女方的純潔與尊嚴\n物品：帽子飛落=男方失去尊嚴/地位的象徵", "2.1敘事視角": "第三人稱：「За метелью добрый молодец идёт」(青年隨暴風雪走來)\n「Да пожалей, душа, ревнивого, жена」(我的老婆，請憐憫那個忌妒的人)——第二人稱請求\n女性第一人稱：「А я не буду...」(但我不會...)——直接表態", "2.2傾訴對象": "「Да пожалей, душа, ревнивого, жена」——他人請求女方憐憫\n女方以「А я не буду...」直接表態拒絕\n傾訴對象從「被動接受請求」轉為「主動拒絕宣告」", "2.3情節發展": "暴風雪中青年走來→帽子飛落（失去尊嚴）\n被請求去憐憫忌妒的他\n女方明確拒絕：「我不會撿，不會弄髒白手」\n清晰的行動—反應情節", "2.4結局類型": "「А я не буду белых рук своих марать」(我不會弄髒自己的白手)\n以女方的拒絕收尾，後續如何未交代\n帶有一種昂揚的決絕感", "3.1情感表現方式": "「不撿起黑帽」「不弄髒白手」——以具體行動的拒絕象徵情感立場\n暴風雪環境加強了對峙的戲劇張力\n無直接吶喊，但行動本身傳達強烈的驕傲與輕蔑", "3.2行動後果": "女方以行動（不撿帽子）明確劃清界線\n非哭泣也非詛咒，而是帶有尊嚴的拒絕\n強度介於強烈與內斂之間", "3.3時間維度": "「А я не буду...」(但我不會...)——當下的即時表態\n場景集中在暴風雪中帽子飛落的那一刻", "3.4情感強度等級": "行動後果中度（拒絕/離開）＋當下爆發\n女性主動表態的視角使情感顯得有力而非哀傷"}, "lyrics": "Ай, люли, ай люли, ай да люли,\n哎，柳莉，哎柳莉，哎嗒柳莉\nЗа метелью добрый молодец идёт\n一位好青年隨著暴風雪走來\nАй, люли, ай люли, ай да люли,\n哎，柳莉，哎，柳莉，哎，柳莉\nЗа метелью добрый молодец идёт\n一位好青年隨著暴風雪走來\nА метелица, метелица всё метёт,\n啊暴風雪，暴風雪不停吹掃\nА за метелью добрый молодец идёт.\n一位好青年隨著暴風雪走來\nАй, люли, ай люли, ай да люли,\n哎，柳莉，哎，柳莉，哎，柳莉\nА за метелью добрый молодец идёт\n一位好青年隨著暴風雪走來\nАй, слетела да чёрна шляпа с молодца,\n哎，黑色的帽子從青年頭上飛落\nДа пожалей, душа, ревнивого, жена.\n我的愛人，我的老婆，請憐憫那個忌妒的人\nАй, люли, ай люли, ай да люли,\n一位好青年隨著暴風雪走來\nДа пожалей, душа, ревнивого, жена.\n我的愛人，我的老婆，請憐憫那個忌妒的人\nА я не буду чёрну шляпу поднимать，\n但我不會去撿起那頂黑帽\nА я не буду белых рук своих марать.\n我也不會弄髒自己潔白的雙手\nАй, люли, ай люли, ай да люли,\n一位好青年隨著暴風雪走來\nА я не буду белых рук своих марать.\n我也不會弄髒自己潔白的雙手"}, {"id": 10, "batch": 1, "sheet": "範例10 最後我將說", "full_title": "範例10 А напоследок я скажу 最後我將說", "title_ru": "А напоследок я скажу", "title_zh": "最後我將說", "motif": "背叛", "analysis": {"1.1情感關鍵詞": {"指標": "沉淪類、背叛類（毀滅、瘋狂、告別）", "分類": "▪ 背叛類詞彙\n▪ 沉淪類詞彙\n▪ 痛苦類詞彙"}, "1.2行動關鍵詞": {"指標": "告別（最後的宣告）", "分類": "▪ 詛咒／祝福\n▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "身體意象（太陽穴/雙手）＋感官消逝意象", "分類": "▪ 物品意象\n▪ 自然意象"}, "2.1敘事視角": {"指標": "第一人稱（女性視角的最後告白）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（直接的告別宣告）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（臨別瞬間的意識流）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "悲劇結局偏開放（告別，但升華抑或瘋狂未明）", "分類": "▪ 悲劇結局（死亡／永遠分離）\n▪ 開放式結局（未知）"}, "3.1情感表現方式": {"指標": "直接高昂（宣告式）＋隱喻（身體意象）", "分類": "▪ 直接高昂吶喊／控訴\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "強烈（精神崩潰邊緣＋帶有控訴的告別）", "分類": "▪ 強烈：仇恨／永不相見"}, "3.3時間維度": {"指標": "當下爆發（告別的此刻）", "分類": "▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "強烈（精神崩潰式的告別宣言）", "分類": "▪ 強烈"}}, "evidence": {"1.1情感關鍵詞": "「с ума схожу」(陷入瘋狂)\n「восхожу к высокой степени безумства」(升華至瘋狂的最高境界)\n「погубил」(毀滅)、「погибели」(毀滅)\n「пали руки」(雙手已無力)——身體的崩潰", "1.2行動關鍵詞": "「Прощай」(再見/告別)\n「любить не обязуйся!」(別承諾去愛！)——帶有警告式的告別\n「А напоследок я скажу...」反覆的宣告式語句", "1.3意象關鍵詞": "身體：「работу малую висок ещё вершит」(太陽穴微微仍在跳動)、「пали руки」(雙手已無力)\n消逝：「уходят запахи и звуки」(氣味與聲音斜斜消逝)——感官的瓦解，暗示意識的離去", "2.1敘事視角": "「я скажу」(我將說)、「С ума схожу」(我陷入瘋狂)\n全曲以「我」的最後陳述為核心，帶有臨別宣言的性質", "2.2傾訴對象": "「Прощай, любить не обязуйся!」(再見，別承諾去愛！)——直接告別\n「Как ты любил, Ты пригубил погибели...Ты погубил, Но погубил так неумело」(你曾如何愛過，你曾毀滅，但卻毀滅得如此笨拙)——直接對話愛人", "2.3情節發展": "全曲停留在「告別的當下」\n意識流動：瘋狂/升華？→指控對方拙劣的毀滅→身體的崩潰信號→再次告別\n非事件敘事，而是情感狀態的流洩", "2.4結局類型": "「С ума схожу иль восхожу к высокой степени безумства」(陷入瘋狂還是升華？)\n「Прощай」是告別，但「升華/瘋狂」的二選一留下解釋的開放性", "3.1情感表現方式": "反覆的「А напоследок я скажу...」——高昂宣告\n「Прощай, любить не обязуйся!」——直接控訴告別\n「уходят запахи и звуки」——感官消逝的詩意隱喻", "3.2行動後果": "「С ума схожу」(陷入瘋狂)——精神崩潰\n「пали руки」(雙手已無力)——身體的崩潰信號\n「Но погубил так неумело」(毀滅得如此笨拙)——在告別中對愛人的輕蔑控訴", "3.3時間維度": "「А напоследок я скажу」(最後我將說)——明確的當下時間點\n身體信號（太陽穴跳動、雙手無力）都是此刻的感受", "3.4情感強度等級": "「行動後果強烈（精神崩潰＋告別控訴）」＋「當下爆發」＋「直接高昂吶喊」\n以臨別宣言形式爆發，帶有尊嚴的毀滅美學"}, "lyrics": "А напоследок я скажу…\n最後我將說…\nА напоследок я скажу…\n最後我將說…\nПрощай, любить не обязуйся!\n再見了，別承諾去愛！\nС ума схожу иль восхожу\n我究竟是發瘋了還是升華\nК высокой степени безумства\n至瘋狂的最高境界\nКак ты любил,\n你曾如何愛過，\nТы пригубил погибели…\n你曾淺嘗毀滅…\nНе в этом дело!\n問題不在這裡！\nКак ты любил,\n你曾如何愛過，\nТы погубил,\n你曾毀滅，\nНо погубил так неумело…\n但卻毀滅得如此笨拙…\nА напоследок я скажу…\n最後我將說…\nРаботу малую висок\n太陽穴微微跳動\nЕще вершит, но пали руки\n仍在繼續，但雙手已無力\nИ стайкою наискосок\n成群地斜斜離去\nУходят запахи и звуки\n消逝的是氣味與聲音\nА напоследок я скажу…\n最後我將說…\nА напоследок я скажу…\n最後我將說…\nПрощай, любить не обязуйся!\n再見了，別承諾去愛！\nС ума схожу иль восхожу\n我究竟是陷入瘋狂還是升華\nК высокой степени безумства\n至瘋狂的最高境界\nТак напоследок я скажу..\n這就是我最後要說的.."}, {"id": 11, "batch": 1, "sheet": "範例11 Мой костёр 我的篝火在霧中閃耀", "full_title": "範例11 Мой костёр 我的篝火在霧中閃耀", "title_ru": "Мой костёр", "title_zh": "我的篝火在霧中閃耀", "motif": "女性的沉淪", "analysis": {"1.1情感關鍵詞": {"指標": "思念類、背叛類（主動離別，帶有預見他人取代的痛苦）", "分類": "▪ 思念類詞彙\n▪ 背叛類詞彙"}, "1.2行動關鍵詞": {"指標": "離開（女方主動，遵循吉普賽流浪的宿命）", "分類": "▪ 離開／留下"}, "1.3意象關鍵詞": {"指標": "物品意象（篝火/披肩/結）＋自然意象（霧/草原）", "分類": "▪ 物品意象\n▪ 自然意象"}, "2.1敘事視角": {"指標": "第一人稱（女性敘事者，主動告別視角）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（直接呼告「我的雄鷹」）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "有明確情節轉折（夜晚最後相聚→橋上道別→吉普賽女子隨車隊離去→請求記憶）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "悲劇結局（永遠分離，預見被取代）", "分類": "▪ 悲劇結局（死亡／永遠分離）"}, "3.1情感表現方式": {"指標": "敘述性表達＋隱喻（篝火/霧/結）", "分類": "▪ 敘述性表達\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "中度（主動離別、預見取代，帶有平靜接受的宿命感）", "分類": "▪ 中度：離開"}, "3.3時間維度": {"指標": "持續性＋永恆性（今夜→明晨離去→未來他人取代）", "分類": "▪ 持續性（一段時間）\n▪ 永恆性（永遠／一生）"}, "3.4情感強度等級": {"指標": "中度（宿命式的主動告別，非憤怒也非毀滅）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「простимся」(我們將道別)——主動選擇的告別\n「Вспоминай, коли другая...будет петь на коленях у тебя!」\n(當有別的女子坐在你膝上唱歌時，記得我)——預見被取代的痛苦\n「судьбу предскажет」(占卜命運)——對未來的不確定與恐懼", "1.2行動關鍵詞": "「Я уйду с толпой цыганок За кибиткой кочевой」(我將隨著一群吉普賽女子離去，跟隨流浪的帳篷車隊)\n「Мы простимся на мосту」(我們將在橋上道別)\n主動離開是全曲最核心的行動", "1.3意象關鍵詞": "物品：「костёр в тумане」(霧中篝火)——短暫溫暖，終將熄滅；「шаль с каймою」(有花邊的披肩)——離別信物；「узел」(結)——曾經的連結\n自然：「туман」(霧)——模糊不清的前途；「степь」(草原)——吉普賽流浪的宿命空間；「искры гаснут на лету」(火星熄滅)——愛情消逝的隱喻", "2.1敘事視角": "「Я уйду с толпой цыганок」(我將隨著吉普賽女子離去)\n「Кто-то завтра...на груди моей развяжет узел, стянутый тобой?」\n(明天會有誰在我的胸前解開你繫的那個結？)——以女性身體承載離別的痛苦", "2.2傾訴對象": "「Кто-то завтра, сокол мой」(明天會有誰呢，我的雄鷹)\n「Вспоминай, коли другая...」(當有別的女子...記得我)\n直接向愛人說話，帶有囑咐與痛苦的雙重色彩", "2.3情節發展": "現在：篝火在霧中燃燒，夜晚的最後相聚\n告別：橋上道別，把披肩結打在身上\n未來：清晨隨吉普賽女子離去，進入草原\n囑咐：當有別的女子取代我時，記得我", "2.4結局類型": "「Я уйду...За кибиткой кочевой」——永遠離去，遵循流浪宿命\n「Вспоминай, коли другая...на коленях у тебя!」——已預見他人取代自己\n「Кто-то...развяжет узел, стянутый тобой?」——那個結終將被他人解開", "3.1情感表現方式": "篝火在霧中燃燒=短暫愛情在不確定中消逝\n「искры гаснут на лету」(火星熄滅)=愛情的終結\n披肩的結=連結，問誰來解開=預見他人取代\n以具體物件承載情感，非直接吶喊", "3.2行動後果": "「Я уйду」(我將離去)——主動選擇離開，非被迫\n「Вспоминай...」——只是請求對方記得，非詛咒\n痛苦是預見被取代，但接受了吉普賽流浪的宿命", "3.3時間維度": "「Мы простимся на мосту」——今夜\n「Я уйду...За кибиткой кочевой」——清晨離去，永遠的流浪\n「Вспоминай, коли другая...」——對未來（有別的女子時）的預見", "3.4情感強度等級": "行動後果中度（離開）＋持續至永恆＋敘述性表達\n情感以宿命的平靜包裹巨大的痛苦\n與範例3（漫長的道路）同屬「接受命運的離別」，但此曲更具女性主體性"}, "lyrics": "Мой костер в тумане светит;\n我的篝火在霧中閃耀；\nИскры гаснут на лету...\n火星在飛舞中熄滅......\nНочью нас никто не встретит;\n夜裡不會有人遇見我們；\nМы простимся на мосту.\n我們將在橋上道別。\nНочь пройдет --- и спозаранок\n夜晚過去------清晨時分，\nВ степь, далёко, милый мой,\n在草原深處，遠方啊，我的愛人，\nЯ уйду с толпой цыганок\n我將隨著一群吉普賽女子離去，\nЗа кибиткой кочевой.\n跟隨那流浪的帳篷車隊。\nНа прощанье шаль с каймою\n臨別時，把那有花邊的披肩\nТы на мне узлом стяни:\n替我在身上打個結：\nКак концы ее, с тобою\n就像它的兩端一樣，\nМы сходились в эти дни.\n這些日子裡我們曾相聚。\nКто-то мне судьбу предскажет?\n會有人為我占卜命運嗎？\nКто-то завтра, сокол мой,\n明天會有誰呢，我的雄鷹，\nНа груди моей развяжет\n在我的胸前解開\nУзел, стянутый тобой?\n你親手繫上的那個結？\nВспоминай, коли другая,\n當有別的女子，\nДруга милого любя,\n愛著你、我的摯愛，\nБудет песни петь, играя\n唱著歌，嬉戲著，\nНа коленях у тебя!\n坐在你的膝上時，\nМой костер в тумане светит;\n我的篝火在霧中閃耀；\nИскры гаснут на лету...\n火星在飛舞中熄滅......\nНочью нас никто не встретит;\n夜裡不會有人遇見我們；\nМы простимся на мосту.\n我們將在橋上道別。"}, {"id": 12, "batch": 1, "sheet": "範例12 Отойди, не гляди 走開，別再看", "full_title": "範例12 Отойди, не гляди 走開，別再看", "title_ru": "Отойди, не гляди", "title_zh": "走開，別再看", "motif": "女性的沉淪", "analysis": {"1.1情感關鍵詞": {"指標": "痛苦類、背叛類（被迫的拒絕，身不由己之痛）", "分類": "▪ 痛苦類詞彙\n▪ 背叛類詞彙"}, "1.2行動關鍵詞": {"指標": "驅離（命令對方離開）＋揭示命運的無力", "分類": "▪ 攻擊／收手\n▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "物品意象（十字架/美貌）＋身體意象（心/胸）", "分類": "▪ 物品意象"}, "2.1敘事視角": {"指標": "第一人稱（女性，被動命運中的主動驅離）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（直接命令式呼告，驅離他）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（命令驅離→揭示命運→再次驅離的循環）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "開放式偏悲劇（命令對方離去，但自身命運已被決定）", "分類": "▪ 開放式結局（未知）\n▪ 悲劇結局（死亡／永遠分離）"}, "3.1情感表現方式": {"指標": "直接高昂吶喊（反覆的命令式驅離）＋敘述性表達（揭示命運）", "分類": "▪ 直接高昂吶喊／控訴\n▪ 敘述性表達"}, "3.2行動後果": {"指標": "中度偏強（驅離、揭示被出賣的命運，無力抵抗）", "分類": "▪ 中度：離開\n▪ 強烈：仇恨／永不相見"}, "3.3時間維度": {"指標": "當下爆發（此刻驅離的緊迫瞬間）", "分類": "▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "中度偏強（命令式的自我保護，痛苦中帶著尊嚴）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「Сердце ноет в груди」(心中滿是悲痛)——非憤怒而是疼痛\n「нету сил ни каких」(我已無任何力氣)——身心俱疲\n「продадут」(他們會出賣我)——被出賣的命運，帶有背叛的結構", "1.2行動關鍵詞": "「Отойди, не гляди, скройся с глаз ты моих」(走開，別再看，從我眼前消失)\n——反覆的命令語氣，但動機是保護對方或自保\n「не дадут」(他們不會允許)、「продадут」(他們會出賣我)——揭示外力壓制的現實", "1.3意象關鍵詞": "物品：「крест на груди」(胸前的十字架)——唯一的財富，象徵信仰與命運的枷鎖\n「красота」(美貌)——不屬於自己、將被出賣的資產\n身體：「Сердце ноет/бьется в груди」(心在胸中疼痛/跳動)——反覆出現的身體感受，情感的具身化", "2.1敘事視角": "「нету сил ни каких」(我已無任何力氣)\n「Денег нет у меня, только крест на груди」(我身無分文，只有胸前的十字架)\n「Меня с красотой --- продадут」(他們會出賣我和我的美貌)\n全程以「我」的處境與感受為軸心", "2.2傾訴對象": "「Отойди, не гляди, скройся с глаз ты моих」——反覆直接命令愛人離去\n「Для тебя ли моя красота, посуди」(你想想，我的美貌難道是為了你？)——質問愛人\n驅離的動作本身即是傾訴", "2.3情節發展": "全曲在「走開，別看我」的反覆命令中循環\n中段插入命運揭示：「他們不允許、他們會出賣我」\n無事件發展，是當下精神崩潰邊緣的情感爆發", "2.4結局類型": "「Меня с красотой --- продадут, продадут」(他們會出賣我)——命運已定\n「Отойди, не гляди」作為收尾——驅離完成，但女性自身的命運仍未改變\n悲劇在於她無力改變被出賣的處境", "3.1情感表現方式": "「Отойди, не гляди!」反覆的高昂命令——直接爆發\n「Мне блаженства с тобой не дадут」(他們不會允許我與你共享幸福)——以陳述語氣揭示外力壓制\n命令與陳述的交替構成情感的張力", "3.2行動後果": "命令愛人離去——中度（驅離）\n「продадут, продадут」(他們會出賣我)——被出賣的命運是強烈的外力壓迫\n女性自身的無力感（нету сил）使強度上升", "3.3時間維度": "「скройся с глаз ты моих」(從我眼前消失)——此刻的緊迫命令\n「Сердце ноет/бьется в груди」——當下身體感受的即時描述\n全曲無回憶也無對未來的想像，完全活在驅離的這一瞬間", "3.4情感強度等級": "行動後果中度偏強＋當下爆發＋直接吶喊\n情感的核心矛盾：愛著對方卻必須驅離，被迫選擇的痛苦\n「只有胸前的十字架」帶出尊嚴感，使強度不至於毀滅性"}, "lyrics": "Отойди, не гляди, скройся с глаз ты моих,\n走開，別再看，從我眼前消失吧，\nСердце ноет в груди, нету сил ни каких.\n心中滿是悲痛，我已無任何力氣。\nСердце ноет в груди, нету сил ни каких,\n心中滿是悲痛，我已無任何力氣，\nОтойди, не гляди, скройся с глаз ты моих.\n走開，別再看，從我眼前消失吧。\nДля тебя ли моя красота, посуди，\n你想想，我的美貌難道是為了你？\nДенег нет у меня, только крест на груди.\n我身無分文，只有胸前的十字架。\nДенег нет у меня, только крест на груди,\n我身無分文，只有胸前的十字架，\nОтойди, не гляди.\n走開，別再看。\nМне блаженства с тобой не дадут, не дадут,\n他們不會允許我與你共享幸福，\nА меня с красотой --- продадут, продадут,\n而他們會出賣我和我的美貌，\nА меня с красотой --- продадут, продадут,\n而他們會出賣我和我的美貌，\nОтойди, не гляди.\n走開，別再看。\nОтойди, не гляди, скройся с глаз ты моих,\n走開，別再看，從我眼前消失吧，\nСердце бьется в груди, нету сил ни каких.\n心在胸中跳動，我已無任何力氣。\nСердце бьется в груди, нету сил ни каких,\n心在胸中跳動，我已無任何力氣，\nОтойди, не гляди.\n走開，別再看。"}, {"id": 13, "batch": 2, "sheet": "範例1 Гитара ты моя 妳是我的吉他", "full_title": "範例1 Гитара ты моя 妳是我的吉他", "title_ru": "Гитара ты моя", "title_zh": "妳是我的吉他", "motif": "思念與痛苦", "analysis": {"1.1情感關鍵詞": {"指標": "愛戀類、渴望類（對吉他的溫柔寄情）", "分類": "▪ 愛戀類詞彙\n▪ 思念類詞彙"}, "1.2行動關鍵詞": {"指標": "等待、陪伴（共度夜晚）", "分類": "▪ 離開／留下\n▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "物品意象（吉他/七弦琴）＋自然意象（晚霞/夜鶯）", "分類": "▪ 物品意象\n▪ 自然意象"}, "2.1敘事視角": {"指標": "第一人稱（夜晚獨自等待的人）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對大自然/物品（直接呼告吉他）", "分類": "▪ 對大自然／物品"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（等待夜晚、吉他到來、心潮澎湃）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "開放式（夜晚未盡，渴望繼續相陪）", "分類": "▪ 開放式結局（未知）"}, "3.1情感表現方式": {"指標": "隱喻/暗示（以吉他代替真實的愛人）＋敘述性表達", "分類": "▪ 隱喻／暗示\n▪ 敘述性表達"}, "3.2行動後果": {"指標": "內斂（等待、相陪、不願入睡）", "分類": "▪ 內斂：思念／沉默／等待"}, "3.3時間維度": {"指標": "當下爆發（某一特定夜晚的陪伴時光）", "分類": "▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "內斂（最輕盈溫柔的曲目之一）", "分類": "▪ 內斂"}}, "evidence": {"1.1情感關鍵詞": "「желанная」(我渴望的)\n「нежно-милые」(溫柔可愛的)話語\n「сердце колышется」(心潮澎湃)\n情感輕柔愉悅，以等待與心跳表達渴望", "1.2行動關鍵詞": "「Приходишь ты, желанная, Со мной вечеровать」(我渴望的妳才會來，與我共度夜晚)\n「Зачем я буду спать?」(我為何還要入睡)——以拒絕入睡表達渴望繼續陪伴", "1.3意象關鍵詞": "物品：「гитара семиструнная」(七弦吉他)——吉普賽音樂象徵，同時是傾訴夥伴\n自然：「зорька ясная」(明亮的晚霞)——夜晚到來的信號；「трели соловья」(夜鶯的啼囀)——美妙動人的比喻", "2.1敘事視角": "「Подружка ты моя」(妳是我的好朋友)\n「Зачем я буду спать?」(我為何還要入睡)\n以第一人稱呈現對吉他的等待與陪伴", "2.2傾訴對象": "「Гитара ты моя, Подружка ты моя」(妳是我的吉他，妳是我的好朋友)\n全曲以「妳」稱呼吉他，是傾訴的唯一對象", "2.3情節發展": "晚霞熄滅→吉他到來→溫柔話語流淌→「再見，明天見」→心潮澎湃不願入睡\n情緒流動輕盈，無戲劇轉折", "2.4結局類型": "「Зачем я буду спать?」(我為何還要入睡)以問句收尾\n渴望繼續，夜晚仍在，無悲劇也無明確結局", "3.1情感表現方式": "吉他=渴望的伴侶，此為核心隱喻\n「сердце колышется」(心潮澎湃)以身體感受間接表達情感\n無吶喊，以溫柔輕語貫穿全曲", "3.2行動後果": "「подожду」式的等待是全曲最強的行動\n無悲劇後果，無詛咒，以不願入睡表達對陪伴的珍視", "3.3時間維度": "「Лишь станет зорька ясная За речкой потухать」(只有當晚霞熄滅時)\n時間錨定在某一個夜晚，晚霞到天亮之間", "3.4情感強度等級": "行動後果內斂＋當下爆發＋隱喻表達\n全曲無悲傷、無失落，以溫柔陪伴為情感核心"}, "lyrics": "妳是我的吉他\nГитара ты моя -\n妳是我的吉他，\nБеспечная и юная -\n無憂無慮又年輕，\nКак трели соловья -\n如同夜鶯的啼囀，\nГитара семиструнная -\n七弦吉他啊，\nПодружка ты моя -\n妳是我的好朋友。\nЛишь станет зорька ясная -\n只有當明亮的晚霞，\nЗа речкой потухать -\n在河對岸漸漸熄滅時，\nПриходишь ты,желанная -\n我渴望的妳，才會來臨，\nСо мной вечеровать -\n與我共度夜晚。\nИ речи нежно-милые -\n而那些溫柔可愛的\nЧто трогают сердца -\n觸動心弦的話語，\nБеспечные,игривые -\n無憂無慮的嬉戲之詞，\nПольются без конца -\n會無盡地流淌。\nПрощай, до завтра!-слышится -\n「再見，明天見！」- 聽見了，\nА милой не видать -\n卻看不見親愛的人。\nА сердце так колышется… -\n而心潮如此澎湃…\nЗачем я буду спать? -\n我為何還要入睡？\nБеспечная и юная -\n無憂無慮又年輕，\nКак трели соловья -\n如同夜鶯的啼囀，\nГитара семиструнная -\n七弦吉他啊，\nПодружка ты моя -\n妳是我的好朋友。"}, {"id": 14, "batch": 2, "sheet": "範例2 Мы долго шли рядом 並肩同行", "full_title": "範例2 Мы долго шли рядом 我們曾長久並肩同行", "title_ru": "Мы долго шли рядом", "title_zh": "我們曾長久並肩同行", "motif": "思念與痛苦", "analysis": {"1.1情感關鍵詞": {"指標": "思念類、痛苦類（沉默錯過的遺憾）", "分類": "▪ 思念類詞彙\n▪ 痛苦類詞彙"}, "1.2行動關鍵詞": {"指標": "沉默（未曾開口）、道歉（終於說出唯一的話）", "分類": "▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "物品意象（道路）為核心", "分類": "▪ 物品意象"}, "2.1敘事視角": {"指標": "第一人稱（回望的遺憾者）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對聽眾（敘述性傾訴，無直接呼告對象）", "分類": "▪ 對聽眾\n▪ 對自己"}, "2.3情節發展": {"指標": "有明確情節轉折（並肩同行→沉默→道路分岔→只剩一句對不起）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "悲劇結局（永遠錯過，道路已分）", "分類": "▪ 悲劇結局（死亡／永遠分離）"}, "3.1情感表現方式": {"指標": "敘述性表達（冷靜陳述遺憾）＋隱喻（道路=關係）", "分類": "▪ 敘述性表達\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "內斂（道別，說出對不起）", "分類": "▪ 內斂：思念／沉默／等待"}, "3.3時間維度": {"指標": "持續性＋當下爆發（曾長久並肩→此刻終於開口）", "分類": "▪ 持續性（一段時間）\n▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "內斂（以克制的語氣承載錯過之痛）", "分類": "▪ 內斂"}}, "evidence": {"1.1情感關鍵詞": "「печальное слово — прости!」(悲傷的詞——對不起)\n「молчанья」(沉默)——壓抑未說出口的話\n「надежд и желаний теснилось так много」(希望與憧憬如此洶湧)——遺憾的反面", "1.2行動關鍵詞": "「мы не решились молчанья прервать」(我們始終不敢打破沉默)\n「Осталось одно только слово... прости!」(只剩一個詞——對不起)\n全曲的核心張力就是「說不出口」與「最後說出對不起」的對比", "1.3意象關鍵詞": "「Мы долго шли рядом одною дорогой」(我們長久沿同一條路並行)\n「круто расходятся наши пути」(我們的道路毅然分岔)\n道路=人生旅程與關係，分岔=無法挽回的分離", "2.1敘事視角": "「Теперь все начать мне хотелось бы снова」(如今我多想重新開始)\n「Что делать?」(奈何？)——個人的無力與遺憾", "2.2傾訴對象": "無直接的「你」作為呼告對象\n以第一人稱嘆息陳述，語氣像是向聽眾說出壓抑已久的遺憾", "2.3情節發展": "過去：兩人並肩同行，有千言萬語卻未說出\n轉折：「но мы не решились молчанья прервать」(卻不敢打破沉默)\n現在：道路分岔，「что делать?」——只剩「對不起」", "2.4結局類型": "「круто расходятся наши пути」(道路毅然分岔)\n最後只剩「прости」(對不起/原諒我)——無法挽回的道別", "3.1情感表現方式": "全曲以平靜的陳述語氣回顧——無吶喊、無詛咒\n「道路分岔」是唯一的比喻，承載了全部的分離之痛", "3.2行動後果": "最終的行動只是說出「прости」(對不起)\n沉默與錯過是主要狀態，非外在的激烈行動", "3.3時間維度": "「Мы долго шли рядом」(我們長久並肩)——持續性\n「Теперь все начать мне хотелось бы снова」——此刻的遺憾爆發", "3.4情感強度等級": "行動後果內斂（只說出對不起）＋敘述性表達\n情感最深沉處是「千言萬語說不出口」的沉默，而非爆發"}, "lyrics": "我們曾長久並肩同行\n我們曾長久一路並肩同行\nМы долго шли рядом одною дорогой,\n萬千話語深藏心中\nИ много хотелось друг другу сказать,\n希望與憧憬如此洶湧\nНадежд и желаний теснилось так много;\n卻始終不敢打破沉默\nНо мы не решились молчанья прервать.\n如今我多想重新開始\nТеперь все начать мне хотелось бы снова;\n但我們的道路已毅然分岔\nНо круто расходятся наши пути.\n奈何？唯剩最後一詞\nЧто делать? Осталось одно только слово\n便是那悲傷之詞------對不起！\nИ это печальное слово --- прости!"}, {"id": 15, "batch": 2, "sheet": "範例3 Слушайте 請聽吧若您願意", "full_title": "範例3 Слушайте, если хотите 請聽吧，若您願意", "title_ru": "Слушайте, если хотите", "title_zh": "請聽吧，若您願意", "motif": "義務與激情", "analysis": {"1.1情感關鍵詞": {"指標": "愛戀類、渴望類（珍惜當下夜晚的急切感）", "分類": "▪ 愛戀類詞彙\n▪ 思念類詞彙"}, "1.2行動關鍵詞": {"指標": "訴說/分享（以歌曲袒露靈魂）", "分類": "▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "自然意象（海浪/夜晚）＋身體意象（心）", "分類": "▪ 自然意象"}, "2.1敘事視角": {"指標": "第一人稱（向愛人分享靈魂的訴說者）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（以вы尊稱，親密而有禮）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（當下的珍惜與害怕失去）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "開放式偏悲（害怕夜晚消逝，無法重返）", "分類": "▪ 開放式結局（未知）"}, "3.1情感表現方式": {"指標": "敘述性表達＋隱喻（以翱翔浪尖比喻與對方共處）", "分類": "▪ 敘述性表達\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "內斂（以歌曲傾訴，珍惜當下）", "分類": "▪ 內斂：思念／沉默／等待"}, "3.3時間維度": {"指標": "當下爆發（珍惜此刻這個夜晚）", "分類": "▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "內斂（溫柔珍惜，非爆發性）", "分類": "▪ 內斂"}}, "evidence": {"1.1情感關鍵詞": "「отрадно」(歡欣)\n「сердце стучит сильней」(心更猛烈地搏動)\n「боюсь, что невозможно мне эту ночь вернуть」(只恐再也不能重擁此夜)——以害怕失去表達珍愛", "1.2行動關鍵詞": "「Открою всю душу свою」(向您袒露我的靈魂)\n「Песню я вам спою」(我將為您唱支歌曲)\n以唱歌/訴說作為最核心的行動", "1.3意象關鍵詞": "自然：「носиться над волнами」(翱翔浪尖)——與對方共處的歡欣感受\n「тихой ночью」(靜謚的夜)——珍貴的當下時光\n身體：「сердце сильней стучит」(心更猛烈地搏動)", "2.1敘事視角": "「Открою всю душу свою」\n「Не дремлет мое сердце」\n全程以「我」的當下感受與渴望為中心", "2.2傾訴對象": "「Слушайте, если хотите」(請聽吧，若您願意)——以вы稱呼\n「Мне так отрадно с вами」(與您共翱翔是何等歡欣)\n「вам」貫穿全曲，直接對愛人傾訴", "2.3情節發展": "全曲停留在「此刻與您共處」的靜謚夜晚\n情緒弧線：歡欣→心更強烈跳動→害怕無法重擁此夜", "2.4結局類型": "「боюсь, что невозможно мне эту ночь вернуть」(只恐再也不能重擁此夜)\n以「害怕失去」而非「已然失去」作結，開放但隱含憂鬱", "3.1情感表現方式": "「носиться над волнами」(翱翔浪尖)——歡欣的意象\n以「唱歌袒露靈魂」作為情感表現的核心行動\n語氣溫柔，無吶喊", "3.2行動後果": "行動只是「唱歌」與「袒露靈魂」\n「умчаться мне было б не жаль」(縱使永逝亦無憾)——極致的投入，但以假設語氣表達", "3.3時間維度": "「этой тихой ночью」(在這靜謚的夜裡)——當下時間點\n「мне эту ночь вернуть」——對「此夜」的執著，強調當下的唯一性", "3.4情感強度等級": "行動後果內斂＋當下爆發＋敘述性表達\n情感以「害怕失去」的溫柔形式流露，無激烈衝突"}, "lyrics": "Слушайте, если хотите,\n請聽吧，若您願意，\nПесню я вам спою\n我將為您唱支歌曲，\nИ в звуках песни этой\n願在這旋律之中\nОткрою всю душу свою.\n向您袒露我的靈魂。\nМне так отрадно с вами\n與您共翱翔浪尖之上\nНоситься над волнами,\n是何等歡欣，\nЧто в безвозвратную даль\n縱使永逝於\nУмчаться мне было б не жаль.\n無歸的遠方亦無憾。\nИ этой тихой ночью,\n在這靜謚的夜裡，\nКогда кругом все спит,\n萬物沉入夢境，\nНе дремлет мое сердце,\n我的心卻清醒著，\nОно сильней стучит.\n更猛烈地搏動。\nВ душу же так тревожно,\n靈魂如此焦灼不安，\nБоюсь, что невозможно\n只恐再也不能\nЕще когда-нибудь\n即使是片刻\nМне эту ночь вернуть.\n重擁此夜時光。"}, {"id": 16, "batch": 2, "sheet": "範例4 Не уезжай 別離開我親愛的人", "full_title": "範例4 Не уезжай, мой голубчик 別離開我，親愛的人", "title_ru": "Не уезжай, мой голубчик", "title_zh": "別離開我，親愛的人", "motif": "義務與激情", "analysis": {"1.1情感關鍵詞": {"指標": "思念類、痛苦類、愛戀類（懇求不要離去）", "分類": "▪ 思念類詞彙\n▪ 愛戀類詞彙\n▪ 痛苦類詞彙"}, "1.2行動關鍵詞": {"指標": "哭泣/祈求（懇求承諾與留下）", "分類": "▪ 哭泣／祈求\n▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "身體意象（心如死）", "分類": "▪ 物品意象"}, "2.1敘事視角": {"指標": "第一人稱（守候者的懇求視角）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（直接懇求式呼告）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（停在離別前懇求的當下）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "開放式（懇求是否被接受未知）", "分類": "▪ 開放式結局（未知）"}, "3.1情感表現方式": {"指標": "直接高昂（反覆懇求）＋敘述性表達", "分類": "▪ 直接高昂吶喊／控訴\n▪ 敘述性表達"}, "3.2行動後果": {"指標": "中度（反覆懇求、宣告失去對方如失去生命）", "分類": "▪ 中度：哭泣／祈求"}, "3.3時間維度": {"指標": "當下爆發（離別前的懇求時刻）＋持續性", "分類": "▪ 當下爆發（此時此刻）\n▪ 持續性（一段時間）"}, "3.4情感強度等級": {"指標": "中度（熱切懇求，以生命作比）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「Печальна жизнь мне без тебя」(沒有你的人生多麼憂傷)\n「Грустна, задумчива сижу」(我憂鬱地獨坐沉思)\n「мне кажется — я не живу」(彷彿生命已然終止)", "1.2行動關鍵詞": "「Не уезжай ты, мой голубчик」(別離開我，親愛的人)\n「Дай на прощанье обещанье」(請在離別時許下承諾)\n「Скажи ты мне, скажи ты мне, Что любишь меня」(告訴我，說你愛我)——反覆的祈求", "1.3意象關鍵詞": "「мне кажется — я не живу」(彷彿生命已然終止)——失去對方=等同死亡\n無明顯自然意象，情感以身體/生命的消失表達", "2.1敘事視角": "「Печальна жизнь мне без тебя」\n「Грустна, задумчива сижу」\n全程以「我」的思念與等待為中心", "2.2傾訴對象": "「Не уезжай ты, мой голубчик」(別離開我，親愛的人)——開篇即直接呼告\n「Скажи ты мне...Что любишь меня」(告訴我...說你愛我)——反覆懇求", "2.3情節發展": "全曲停留在離別前的懇求場景\n描述見不到他時的思念狀態，但無具體事件", "2.4結局類型": "「Скажи ты мне...」以反覆懇求作結\n對方是否留下、是否說出「我愛你」仍未知", "3.1情感表現方式": "「Скажи ты мне, скажи ты мне!」——反覆的高昂懇求\n「мне кажется — я не живу」——以生命消失描述思念的強度", "3.2行動後果": "「Не уезжай」(別離開)的反覆懇求\n「я не живу」(彷彿不再活著)——情感強度已達中度上緣", "3.3時間維度": "「Не уезжай」——此刻的懇求\n「Когда порой тебя не вижу」(當有時見不到你)——描述反覆出現的思念狀態", "3.4情感強度等級": "行動後果中度（祈求）＋當下爆發\n「失去你=失去生命」的宣告使強度達中度，但無詛咒或毀滅"}, "lyrics": "Не уезжай ты, мой голубчик,\n別離開我，親愛的人，\nПечальна жизнь мне без тебя.\n沒有你的人生多麼憂傷。\nДай на прощанье обещанье,\n請在離別時許下承諾，\nЧто не забудешь ты меня.\n說你永遠不會將我遺忘。\nСкажи ты мне, скажи ты мне,\n告訴我，告訴我，\nЧто любишь меня, что любишь меня.\n說你愛我，說你愛我。\nСкажи ты мне, скажи ты мне,\n告訴我，告訴我，\nЧто любишь ты меня.\n說你深愛著我。\nКогда порой тебя не вижу,\n當有時見不到你，\nГрустна, задумчива сижу.\n我憂鬱地獨坐沉思。\nКогда речей твоих не слышу,\n當聽不見你的話語，\nМне кажется - я не живу.\n彷彿生命已然終止。\nСкажи ты мне, скажи ты мне…\n告訴我，告訴我⋯⋯"}, {"id": 17, "batch": 2, "sheet": "範例5 Эй ямщик 嘿車夫快趕往雅爾", "full_title": "範例5 Эй, ямщик, гони-ка к Яру 嘿，車夫，快趕往雅爾", "title_ru": "Эй, ямщик, гони-ка к Яру", "title_zh": "嘿，車夫，快趕往雅爾", "motif": "思念與痛苦", "analysis": {"1.1情感關鍵詞": {"指標": "思念類（以狂歡驅逐憂愁）、沉淪類", "分類": "▪ 思念類詞彙\n▪ 沉淪類詞彙"}, "1.2行動關鍵詞": {"指標": "出發、狂歡、拋撒金幣（以行動逃避思念）", "分類": "▪ 離開／留下\n▪ 殺人／報復"}, "1.3意象關鍵詞": {"指標": "物品意象（三駕馬車/香檳/吉他）＋自然意象（月夜/暴雪）", "分類": "▪ 物品意象\n▪ 自然意象"}, "2.1敘事視角": {"指標": "第一人稱（逃避憂愁的主動者）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對聽眾/朋友（邀約同行的號召）", "分類": "▪ 對聽眾"}, "2.3情節發展": {"指標": "有明確情節轉折（憂愁→決定出發→馬車飛奔→抵達雅爾狂歡至天亮）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "開放式偏和解（以狂歡驅散憂愁，但根本問題未解）", "分類": "▪ 開放式結局（未知）\n▪ 和解結局（放下／祝福）"}, "3.1情感表現方式": {"指標": "直接高昂吶喊（催馬出發的豪放號令）", "分類": "▪ 直接高昂吶喊／控訴"}, "3.2行動後果": {"指標": "中度（以狂歡逃避，拋撒金幣）", "分類": "▪ 中度：離開"}, "3.3時間維度": {"指標": "當下爆發（此刻決定出發的衝動）", "分類": "▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "中度（以豪放行動掩蓋內心憂愁）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「Разогреть шампанским кровь」(讓香檳點燃熱血)\n「Разгоню тоску я прочь」(把心中憂鬱全都驅散)——「тоска」是驅動行動的隱含情感\n「Будем петь, гулять всю ночь」(歌唱狂歡徹夜)——以沉醉逃避", "1.2行動關鍵詞": "「Эй, ямщик, гони-ка к Яру!」(嘿，車夫，快趕往雅爾！)\n「Я раздам им золотые」(我要向她們拋撒金幣)\n「Не жалей лошадей!」(別吝惜鞭策馬兒)——急迫逃離的行動語", "1.3意象關鍵詞": "物品：「тройка」(三駕馬車)——急速出發的象徵；「шампанское」(香檳)——狂歡沉醉；「гитара」(吉他)——歌唱作樂\n自然：「лунной ночью」(月光之夜)；「белой вьюгой」(白雪紛飛)——夜晚飛奔的意象", "2.1敘事視角": "「Я раздам им золотые」(我要向她們拋撒金幣)\n「Разгоню тоску я прочь」(我要把憂愁驅散)\n以「我」的主動行動為核心", "2.2傾訴對象": "「Эй, ямщик!」(嘿，車夫！)——直接呼喚行動者\n「Отогреемся, друзья!」(朋友們，讓我們暖徹心扉！)\n具有號召感，呼告朋友/聽眾同行", "2.3情節發展": "起因：「тоска」(憂鬱)驅動出發\n行動：催促車夫，馬車飛奔月夜\n目標：雅爾酒館，吉普賽女郎，歌唱至天明\n情節完整，具有出發到抵達的弧線", "2.4結局類型": "「Будем петь мы до утра」(我們將歌唱至天明)——以歡樂收尾\n憂愁被暫時驅散，但是否真正解決未知", "3.1情感表現方式": "「Эй, ямщик, гони-ка к Яру!」(嘿，車夫，快趕往雅爾！)\n「Не жалей лошадей!」(別吝惜鞭策馬兒！)\n「Вези, брат, веселей!」(跑得更歡快些，兄弟！)——豪放高昂的命令語氣", "3.2行動後果": "「Я раздам им золотые」(拋撒金幣)——行動豪爽但非破壞性\n驅散憂愁是目的，非詛咒或毀滅", "3.3時間維度": "「Эй, ямщик, гони-ка!」——即刻出發的命令\n全曲停在馬車飛奔的當下行動中", "3.4情感強度等級": "行動後果中度（出發狂歡）＋當下爆發＋直接吶喊\n情感的真實核心是「тоска」，但用豪放行動包裝，形成表裡落差"}, "lyrics": "Запеть песню про любовь,\n若要唱一曲情歌，\nАль поехать лучше к Яру -\n不如直奔雅爾酒館------\nРазогреть шампанским кровь.\n讓香檳點燃熱血奔流。\nТам цыганки молодые,\n那兒有年輕的吉普賽女郎，\nБудем петь, гулять всю ночь,\n我們將歌唱狂歡徹夜，\nЯ раздам им золотые,\n我要向她們拋撒金幣，\nРазгоню тоску я прочь.\n把心中憂鬱全都驅散。\nЭй, ямщик, гони-ка к Яру,\n嘿，車夫，快趕往雅爾，\nЭх, лошадей, лошадей, брат, не жалей.\n哎，兄弟，別吝惜鞭策馬兒啊，馬兒啊!\nТройку ты запряг, не пару,\n你套上的是三匹馬，不是一對，\nТак вези, брат, веселей!\n那就跑得更歡快些，兄弟！\nЛунной ночью, белой вьюгой,\n月光之夜，白雪紛飛，\nСнежной пылью занесет.\n漫天雪塵撲面而來。\nВ сани сяду я с подругой,\n我與姑娘同坐雪橇，\nТройка с места понесет.\n三架馬車即刻奔騰而去。\nА когда приедем к Яру,\n當我們抵達雅爾，\nОтогреемся, друзья,\n朋友們，讓我們暖徹心扉，\nИ под звонкую гитару\n在清脆的吉他聲中\nБудем петь мы до утра."}, {"id": 18, "batch": 2, "sheet": "範例6 Снова слышу голос твой 又聽見妳", "full_title": "範例6 Снова слышу голос твой 又聽見妳的聲音", "title_ru": "Снова слышу голос твой", "title_zh": "又聽見妳的聲音", "motif": "思念與痛苦", "analysis": {"1.1情感關鍵詞": {"指標": "痛苦類、沉淪類（後悔愛上，卻無力忘懷）", "分類": "▪ 痛苦類詞彙\n▪ 沉淪類詞彙"}, "1.2行動關鍵詞": {"指標": "沉默（無力做任何事，只能在內心掙扎）", "分類": "▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "顏色意象（黝黑吉普賽女郎）＋自然意象（田野/帳篷）", "分類": "▪ 顏色意象\n▪ 自然意象"}, "2.1敘事視角": {"指標": "第一人稱（後悔愛上卻無法忘記的男性）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（ты，半責備半自嘲）", "分類": "▪ 對愛人\n▪ 對自己"}, "2.3情節發展": {"指標": "有明確情節轉折（聽見聲音→蒼白→後悔愛上→承認無力忘懷）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "悲劇結局（妳不會愛，我無法忘，永遠的困境）", "分類": "▪ 悲劇結局（死亡／永遠分離）"}, "3.1情感表現方式": {"指標": "敘述性表達＋隱喻（疲憊血管/黝黑膚色）", "分類": "▪ 敘述性表達\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "內斂偏中（承認無力忘懷，繼續被困）", "分類": "▪ 內斂：思念／沉默／等待\n▪ 中度：生病"}, "3.3時間維度": {"指標": "當下爆發（此刻聽見聲音）＋持續性", "分類": "▪ 當下爆發（此時此刻）\n▪ 持續性（一段時間）"}, "3.4情感強度等級": {"指標": "中度（無力忘懷的困陷，以克制語氣呈現）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「муку」(痛苦)\n「слышу и бледнею」(聽見而臉色蒼白)——身體化的痛苦反應\n「Не любил бы, не ласкал」(就不會去愛，不會去疼惜)——假設語氣的後悔\n「Я — забыть не в силах」(我無力忘懷)——沉淪的核心", "1.2行動關鍵詞": "全曲無外在行動\n「что ж напрасно горячить Кровь в усталых жилах」(為何徒然燃燒疲憊血管中的血液)——放棄抵抗的內心獨白\n唯一的行動是「繼續記得」", "1.3意象關鍵詞": "顏色：「смуглую цыганку」(黝黑的吉普賽女郎)——以膚色代指神秘的吉普賽愛人\n自然：「В чистом поле под шатром」(在帳篷下的空地上)——吉普賽流浪的生活空間\n身體：「кровь в усталых жилах」(疲憊血管中的血液)——愛情耗盡精力的比喻", "2.1敘事視角": "「Слышу и бледнею」\n「Я — забыть не в силах」\n全程以「我」的後悔與無力感為核心", "2.2傾訴對象": "「Не сумела ты любить」(妳不懂得如何去愛)——對愛人的評斷\n「Я — забыть не в силах」——對自己的無力承認\n在責備對方與承認自己無力之間搖擺", "2.3情節發展": "觸發：「снова слышу голос твой, слышу и бледнею」(又聽見妳的聲音，蒼白了)\n回憶：如果早知痛苦就不會愛\n結論：「не сумела ты любить, Я — забыть не в силах」——妳不會愛，我無法忘", "2.4結局類型": "「не сумела ты любить — Я забыть не в силах」\n兩人的不對稱：她無法愛，他無法忘——形成永久的悲劇閉環", "3.1情感表現方式": "「кровь в усталых жилах」(疲憊血管中的血液)——愛情令人精疲力竭的比喻\n以「臉色蒼白」的身體反應表達情感強度\n無直接吶喊，以後悔的假設語氣敘述", "3.2行動後果": "「слышу и бледнею」(臉色蒼白)——身體反應已是中度信號\n「забыть не в силах」——被動承受，無外在行動", "3.3時間維度": "「снова слышу голос твой」(又聽見妳的聲音)——當下的觸發\n「День и ночь темной...я всё сижу」——持續的等待與記憶", "3.4情感強度等級": "行動後果內斂偏中＋當下爆發＋敘述性表達\n核心矛盾「她不愛，他不忘」形成中度的情感困陷"}, "lyrics": "Снова слышу голос твой -\n又聽見妳的聲音\nСлышу и бледнею -\n聽見而臉色蒼白；\nРасставался, как с душой -\n曾像與靈魂分離般，\nС красотой твоею -\n與妳的美麗告別！\nЕсли б муку эту знал -\n若早知這般痛苦，\nЧуял спозаранку -\n若能預先感知，\nНе любил бы, не ласкал -\n就不會去愛，不會去疼惜\nСмуглую цыганку -\n那黝黑的吉普賽女郎。\nНе лелеял бы потом -\n後來也不會珍愛\nЭтой думы томной -\n這憂鬱的思緒\nВ чистом поле под шатром -\n在帳篷下的空地上\nДнем и ночью темной -\n在白晝與漆黑的夜裡。\nЧто ж напрасно горячить -\n為何要徒然燃燒\nКровь в усталых жилах -\n血液倘留在在疲憊的血管中\nНе сумела ты любить -\n妳不懂得如何去愛，\nЯ - забыть не в силах -\n而我卻無力忘懷。"}, {"id": 19, "batch": 2, "sheet": "範例7 Заря восход 朝霞升起閃耀躍動", "full_title": "範例7 Заря восход играет 朝霞升起，閃耀躍動", "title_ru": "Заря восход играет", "title_zh": "朝霞升起，閃耀躍動", "motif": "義務與激情", "analysis": {"1.1情感關鍵詞": {"指標": "思念類、愛戀類（等待愛人歸來的焦急渴望）", "分類": "▪ 思念類詞彙\n▪ 愛戀類詞彙"}, "1.2行動關鍵詞": {"指標": "等待（徹夜守候、不離營火）", "分類": "▪ 哭泣／祈求\n▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "自然意象（朝霞/營火/月亮）為核心，物品意象次之", "分類": "▪ 自然意象\n▪ 物品意象"}, "2.1敘事視角": {"指標": "第一人稱（女性視角，徹夜守候的等待者）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（直接呼告「我的雄鷹」）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（徹夜守候→朝霞升起→仍在等待）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "開放式偏樂觀（對未來相聚充滿信心）", "分類": "▪ 開放式結局（未知）\n▪ 和解結局（放下／祝福）"}, "3.1情感表現方式": {"指標": "直接高昂（呼告愛人）＋自然意象隱喻", "分類": "▪ 直接高昂吶喊／控訴\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "內斂（徹夜守候，等待）", "分類": "▪ 內斂：思念／沉默／等待"}, "3.3時間維度": {"指標": "持續性（從日落到日出的整夜等待）", "分類": "▪ 持續性（一段時間）"}, "3.4情感強度等級": {"指標": "中度（熱切等待，但以積極信念收尾）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「по тебе душа болит」(我的靈魂因你而疼痛)\n「с нетерпением я жду」(我焦急地等待)\n「вся кровь во мне кипит」(我全身的血液都在沸騰)——渴望的身體化表達", "1.2行動關鍵詞": "「От заката и до восхода, У костра я все сижу」(從日落到日出，我始終坐在營火旁)\n以「守候」作為愛的具體行動，徹夜不離", "1.3意象關鍵詞": "自然：「Заря восход играет」(朝霞升起)——時間流逝的見證；「月光照耀」——夜晚的陪伴\n「костер мой догорает」(我的營火即將燃盡)——愛情/生命力的比喻\n呼告：「сокол мой прекрасный」(我美麗的雄鷹)——對愛人的稱呼", "2.1敘事視角": "「По тебе душа болит」\n「У костра я все сижу」\n「С нетерпением я жду」——全程以「我」的等待為中心", "2.2傾訴對象": "「Где же ты, сокол мой прекрасный?」(你在哪裡，我美麗的雄鷹？)\n以「雄鷹」稱呼愛人，是吉普賽傳統的愛人暱稱", "2.3情節發展": "從「營隊入睡」到「朝霞升起」\n只有等待的動作，愛人始終未出現\n末段轉向樂觀：「我們注定要體會愛情，我們將歌唱和跳舞」", "2.4結局類型": "「Нам с тобою...суждено любовь узнать」(我們注定要體會愛情)\n「Будем петь мы и плясать!」(我們將歌唱和跳舞！)\n以積極信念收尾，非悲劇", "3.1情感表現方式": "「Где же ты, сокол мой прекрасный?」——直接高昂的呼喚\n「костер догорает」(營火即將燃盡)——等待的時間正在消耗的隱喻\n「кровь во мне кипит」(血液沸騰)——渴望的身體化隱喻", "3.2行動後果": "行動只是「坐在營火旁等待」——極度的內斂等待\n未採取任何主動尋找的行動", "3.3時間維度": "「От заката и до восхода」(從日落到日出)——明確的時間跨度\n等待橫跨整個夜晚，是持續性的", "3.4情感強度等級": "行動後果內斂（等待）＋持續性＋直接呼告\n「血液沸騰」的渴望使強度達中度，但末段的樂觀信念中和了悲傷"}, "lyrics": "Светит месяц, светит ясный -\n月光照耀，明亮地照耀，\nТабор наш давно уж спит -\n我們的營隊早已入睡。\nГде же ты, сокол мой прекрасный? -\n你在哪裡，我美麗的雄鷹？\nПо тебе душа болит -\n我的靈魂因你而疼痛。\nЗаря восход играет -\n朝霞升起，閃耀躍動，\nА табор наш уж спит -\n而我們的營隊已然沉睡。\nКостер мой догорает -\n我的營火即將燃盡，\nВся кровь во мне кипит -\n我全身的血液都在沸騰。\nОт заката и до восхода -\n從日落到日出，\nУ костра я все сижу -\n我始終坐在營火旁，\nТвоего, мой друг, прихода -\n你的到來，我的朋友，\nС нетерпением я жду -\n我焦急地等待著。\nЗаря восход играет... -\n朝霞升起，閃耀躍動...\nНам с тобою, друг мой милый -\n我和你，我親愛的朋友，\nСуждено любовь узнать -\n注定要體會愛情。\nТак поэтому беспечно -\n正因如此我們要無憂無慮地\nБудем петь мы и плясать! -\n我們將歌唱和跳舞！\nЗаря восход играет... -\n朝霞升起，閃耀躍動..."}, {"id": 20, "batch": 2, "sheet": "範例8 Капризная 任性又倔強的人", "full_title": "範例8 Капризная, упрямая 任性又倔強的人", "title_ru": "Капризная, упрямая", "title_zh": "任性又倔強的人", "motif": "義務與激情", "analysis": {"1.1情感關鍵詞": {"指標": "愛戀類、痛苦類（年齡差異下的複雜愛情）", "分類": "▪ 愛戀類詞彙\n▪ 痛苦類詞彙"}, "1.2行動關鍵詞": {"指標": "拒絕(命令她離去)/接受(最終獻上生命)的矛盾行動", "分類": "▪ 哭泣／祈求\n▪ 攻擊／收手"}, "1.3意象關鍵詞": {"指標": "自然意象（玫瑰/秋天/春天）為核心，顏色意象次之", "分類": "▪ 自然意象\n▪ 顏色意象"}, "2.1敘事視角": {"指標": "第一人稱（年長男性的自我矛盾）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（以вы尊稱，年長者對年輕女子）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "有明確情節轉折（抗拒→懷疑→最終獻上）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "和解結局（克服疑慮，最終獻上自我）", "分類": "▪ 和解結局（放下／祝福）"}, "3.1情感表現方式": {"指標": "直接高昂吶喊（三次反覆命令/讓步）＋比喻", "分類": "▪ 直接高昂吶喊／控訴\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "中度（獻出生命，但以歡喜收尾）", "分類": "▪ 中度：祈求\n▪ 強烈：仇恨"}, "3.3時間維度": {"指標": "持續性（老者生命的最後春天）＋當下爆發", "分類": "▪ 持續性（一段時間）\n▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "中度偏強（三次矛盾轉折，情感複雜度最高）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「О! Как я Вас люблю!」(哦！我是多麼愛您！)\n「Я для себя своих я слёз感到羞愧」(我為自己的眼淚感到羞愧)\n「последняя весна моя」(這是我最後的春天)——時間的緊迫與自我憐憫", "1.2行動關鍵詞": "「Уйдите! Уйдите! Уйдите!」(走開！走開！走開！)——命令她離去\n「Не лгите! Не лгите! Не лгите!」(別說謊！)——懷疑\n「Возьмите! Возьмите! Возьмите!」(拿去吧！)——最終獻上生命\n三次反覆的命令形成戲劇性的情感弧線", "1.3意象關鍵詞": "自然：「вы сотканы из роз」(妳是由玫瑰織就)——對她美麗的比喻；「последняя весна моя」(我最後的春天)——暗示年老者的最後愛情\n「жизнь мою осеннюю」(我秋天的生命)——以季節比喻人生階段\n顏色：「Вы светлая, лучистая」(您是明亮、光芒四射的)——對年輕女子的描繪", "2.1敘事視角": "「Я старше Вас, дитя моё, стыжусь своих я слёз」(我比妳年長，我為自己的眼淚感到羞愧)\n「осенью окованный」(被秋天束縛的我)\n以第一人稱呈現老者愛上年輕女子的掙扎", "2.2傾訴對象": "「Капризная, упрямая」(任性又倔強的人啊)——直接呼告\n「Дитя моё」(我的孩子)——年齡差異的呼稱\n「мой юноша седой!」(我滿頭白髮的少年！)——她對他的反稱", "2.3情節發展": "第一段：愛上她，為眼淚感到羞愧\n命令她走開→她說「你是我唯一的」\n懷疑她說謊→被她的美好說服\n最終：「拿去吧，我的秋天生命！」", "2.4結局類型": "「Отброшу все сомнения, прощу каприз я Вам」(我將拋開所有疑慮，原諒妳的任性)\n「Возьмите! Возьмите! Возьмите!」(拿去吧！)——完全的自我奉獻", "3.1情感表現方式": "「走開！走開！走開！」「別說謊！」「拿去吧！」——三次高昂的反覆命令形成情緒弧線\n「玫瑰織就」「秋天的生命」「最後的春天」——豐富的自然比喻", "3.2行動後果": "「жизнь мою осеннюю так радостно отдам」(如此欣喜地獻上我秋天的生命)\n強度在「獻上一切」，但以歡欣而非毀滅的方式呈現", "3.3時間維度": "「последняя весна моя」——人生最後階段的時間感\n「Возьмите!」——當下的決定性爆發", "3.4情感強度等級": "行動後果中度（獻上生命但非毀滅性）＋三次情感轉折\n17首中情感複雜度最高的曲目之一"}, "lyrics": "Капризная, упрямая - вы сотканы из роз -\n任性又倔強的人啊---妳是由玫瑰織就\nЯ старше Вас, дитя моё, стыжусь своих я слёз -\n我比妳年長，我的孩子，我為自己的眼淚感到羞愧\nКапризная, упрямая - о! Как я Вас люблю! -\n任性又倔強的人啊---哦！我是多麼愛您！\nПоследняя весна моя, я об одном молю -\n這是我最後的春天，我只祈求一件事\n\"Уйдите! Уйдите! Уйдите!\" -\n「走開！走開！走開！」\nВы шепчете таинственно: \"Мой юноша седой! -\n您神秘地低語：「我滿頭白髮的少年啊！\nТы у меня единственный, один лишь ты такой!\" -\n你是我唯一僅有，獨一無二的人！」\nНо сказкой околдованный, я сам себя бужу -\n但被童話蠱惑的我，將自己喚醒\nИ осенью окованный, дитя, я Вам твержу -\n而被秋天束縛的我，孩子，我對您堅決地說\n\"Не лгите! Не лгите!Не лгите!\" -\n「別說謊！別說謊！別說謊！」\nВы светлая, лучистая, с улыбкой на устах -\n您是明亮、光芒四射的，唇邊帶著微笑\nИ если правда чистая, есть только в тех словах -\n如果純潔的真理只存在於那些話語中\nОтброшу все сомнения, прощу каприз я Вам -\n我將拋開所有疑慮，原諒妳的任性\nИ жизнь мою осеннюю так радостно отдам -\n並如此欣喜地獻上我秋天的生命\n\"Возьмите! Возьмите! Возьмите!\" -\n「拿去吧！拿去吧！拿去吧！」"}, {"id": 21, "batch": 2, "sheet": "範例9 Ты едешь бледная 妳蒼白地駕車離去", "full_title": "範例9 Ты едешь, бледная 妳蒼白地駕車離去", "title_ru": "Ты едешь, бледная", "title_zh": "妳蒼白地駕車離去", "motif": "女性的沉淪", "analysis": {"1.1情感關鍵詞": {"指標": "沉淪類、背叛類（婚外情的複雜心理）", "分類": "▪ 背叛類詞彙\n▪ 沉淪類詞彙"}, "1.2行動關鍵詞": {"指標": "秘密前往情夫處（夜晚偷行）", "分類": "▪ 離開／留下"}, "1.3意象關鍵詞": {"指標": "物品意象（銅製門牌/藍色窗簾/深紅枕頭）＋顏色意象", "分類": "▪ 物品意象\n▪ 顏色意象"}, "2.1敘事視角": {"指標": "第三人稱（旁觀者視角，冷靜描述女主角）", "分類": "▪ 第三人稱（他／她）"}, "2.2傾訴對象": {"指標": "對聽眾（旁觀性的冷靜描述）", "分類": "▪ 對聽眾"}, "2.3情節發展": {"指標": "有明確情節（女主獨自夜行→腦中浮現情夫住處的細節→情夫等待→丈夫也在等）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "開放式偏悲劇（情欲的困陷，無法脫身）", "分類": "▪ 開放式結局（未知）\n▪ 悲劇結局（死亡／永遠分離）"}, "3.1情感表現方式": {"指標": "敘述性表達（旁觀的冷靜分析）＋感官意象", "分類": "▪ 敘述性表達\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "中度偏強（婚外情、精神分裂狀態）", "分類": "▪ 中度：生病\n▪ 強烈：仇恨"}, "3.3時間維度": {"指標": "當下爆發（某個特定的夜晚）", "分類": "▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "中度偏強（以旁觀冷靜包裹的強烈沉淪）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「ты едешь бледная...пьяная」(妳蒼白地...醉醺醺地)——精神與肉體的雙重沉淪\n「смеясь и плача, к нему придёт」(又笑又哭地，會來到他身邊)——矛盾的情感狀態\n「послушная」(順從的她)——對情欲控制的臣服", "1.2行動關鍵詞": "「по тихим улочкам, совсем одна」(沿著寂靜的街道，獨自一人)\n「смеясь и плача, к нему придёт」(又笑又哭地，會來到他身邊)\n「простодушный муж...жену под утро ждёт」(天真的丈夫在黎明前等待妻子)——暗示她整夜未歸", "1.3意象關鍵詞": "物品：「табличка медная」(銅製的門牌)——情夫住處的強迫性記憶；「штора синяя его окна」(他窗戶的藍色窗簾)\n「Коньяк Мартэль, духи Гарсон」(馬爹利白蘭地，Garson香水)——情夫生活的細節，充滿感官記憶\n顏色：「бледная」(蒼白)、「синяя」(藍色)、「алые」(深紅色枕頭)", "2.1敘事視角": "「Ты едешь бледная」——雖用「ты」但語氣像旁觀者分析她的狀態\n「любовник знает: она...к нему придёт」——敘述者切換到情夫的視角\n「простодушный муж...жену ждёт」——旁觀者同時看到三個人", "2.2傾訴對象": "以「ты」稱呼女主，帶有旁觀指點的距離感\n敘述者同時呈現女主的內心、情夫的知曉、丈夫的等待——全知視角", "2.3情節發展": "女主蒼白醉醺地獨自駕車\n腦中反覆出現情夫的門牌與窗簾\n情夫正鋪上深紅枕頭等待\n與此同時，天真的丈夫在家等待\n三角關係的全景呈現", "2.4結局類型": "「смеясь и плача, к нему придёт」(又笑又哭地去找他)——矛盾表示無法自控\n「послушная」(順從的)——暗示她知道這樣不對但無法停止", "3.1情感表現方式": "旁觀者的冷靜語氣反而放大了女主的悲哀\n具體的感官細節（香水、白蘭地、深紅枕頭）=情感記憶的強迫性回放\n「смеясь и плача」(又笑又哭)——矛盾本身即是最強的情感表達", "3.2行動後果": "「бледная, пьяная」(蒼白、醉醺醺)——身體與精神雙重受損\n「смеясь и плача」——精神分裂式的矛盾\n以行動（夜行去情夫處）呈現情感的失控", "3.3時間維度": "「ночью нас никто не встретит」(夜裡不會有人遇見我們)\n整個場景鎖定在這個夜晚的街道與情夫住處", "3.4情感強度等級": "旁觀語氣的冷靜與女主行為的失控形成強烈對比\n感官細節的密度使情感壓力上升至中度偏強"}, "lyrics": "Ты едешь бледная, ты едешь пьяная -\n妳蒼白地駕車離去，妳醉醺醺地駕車離去\nПо тихим улочкам, совсем одна -\n沿著寂靜的街道，獨自一人\nИ всё мерещится табличка медная -\n眼前總浮現那銅製的門牌\nИ штора синяя его окна -\n和他窗戶那藍色的窗簾\nОн надевает подушки алые -\n他鋪上深紅色的枕頭\nКоньяк \"Мартэль\", духи \"Гарсон\" -\n馬爹利白蘭地，Garson香水\nЕго глаза всегда усталые -\n他的眼睛總是疲憊\nА губы пьяные, как хмель -\n而雙唇卻如酒醉般迷離\nПускай в гостиной муж простодушный -\n任憑客廳裡天真的丈夫\nСвою жену под утро ждёт -\n在黎明前等待他的妻子\nЛюбовник знает: она, послушная -\n情夫知道：她，順從的她\nСмеясь и плача, к нему придёт -\n又笑又哭地，會來到他身邊\nТы едешь бледная, ты едешь пьяная -\n妳蒼白地駕車離去，妳醉醺醺地駕車離去\nПо тихим улочкам, совсем одна -\n沿著寂靜的街道，獨自一人\nИ всё мерещится табличка медная -\n眼前總浮現那銅製的門牌\nИ штора синяя его окна -\n和他窗戶那藍色的窗簾"}, {"id": 22, "batch": 2, "sheet": "範例10 Калитка 小門", "full_title": "範例10 Калитка 小門", "title_ru": "Калитка", "title_zh": "小門", "motif": "義務與激情", "analysis": {"1.1情感關鍵詞": {"指標": "愛戀類（秘密相會的期待與渴望）", "分類": "▪ 愛戀類詞彙"}, "1.2行動關鍵詞": {"指標": "秘密相會（輕輕開門、如影子般進入花園）", "分類": "▪ 離開／留下\n▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "自然意象（花園/星辰/稠李樹）＋物品意象（小門/斗篷/蕾絲）", "分類": "▪ 自然意象\n▪ 物品意象"}, "2.1敘事視角": {"指標": "第一人稱（等待愛人到來的男性）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（直接邀約的指令式呼告）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "有明確情節（夜晚到來→邀約進入花園→在亭子邊相遇）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "開放式偏和解（相會在即，充滿美好期待）", "分類": "▪ 開放式結局（未知）\n▪ 和解結局（放下／祝福）"}, "3.1情感表現方式": {"指標": "敘述性表達（細緻描繪相會的每個步驟）＋感官意象", "分類": "▪ 敘述性表達\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "內斂（秘密相會，無悲劇後果）", "分類": "▪ 內斂：思念／沉默／等待"}, "3.3時間維度": {"指標": "當下爆發（某一個星光夜晚的相會時刻）", "分類": "▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "內斂（最輕盈浪漫，無任何悲傷元素）", "分類": "▪ 內斂"}}, "evidence": {"1.1情感關鍵詞": "「Отвори потихоньку калитку」(請輕輕打開那小柵門)——充滿期待的邀請\n「С милых уст кружева отведу」(我將揭開甜美唇上的蕾絲)——對親吻的渴望\n全曲無明確的痛苦，以秘密與期待為情感核心", "1.2行動關鍵詞": "「Войди в тихий садик, как тень」(如影子般步入靜謐的花園)\n「Не забудь потемнее накидку」(別忘了披上深色的斗篷)\n所有行動都是為了不被發現的秘密相會", "1.3意象關鍵詞": "自然：「звезды зажгут небеса」(星辰點亮天際)——夜晚相會的背景\n「черемух серебряный иней」(稠李樹銀白的霜霧)——美麗的夜晚意象\n物品：「калитка」(小柵門)——秘密愛情的入口；「накидку темнее」(深色斗篷)——遮掩身份的偽裝\n「кружева」(蕾絲)——神秘與優雅的象徵", "2.1敘事視角": "「Я незримо, неслышно пройду」(我將無形無聲地走過)\n「С милых уст кружева отведу」(我將揭開甜美唇上的蕾絲)", "2.2傾訴對象": "「Отвори потихоньку калитку」(請輕輕打開那小柵門)\n「Войди в тихий садик, как тень」\n「Не забудь потемнее накидку」——一系列的邀約指令，直接對愛人說", "2.3情節發展": "夜幕降臨，星辰點亮\n男主邀請愛人打開小門、披上深色斗篷悄悄進入\n在枝葉最密處等待\n在亭子邊揭開她唇上的蕾絲", "2.4結局類型": "全曲停在期待相會的邊緣，以「揭開蕾絲」的即將時刻作結\n無悲劇，無分離，是充滿美好期待的開放結局", "3.1情感表現方式": "以一系列具體的指令（開門、披斗篷、進花園）建構相會的期待感\n「如影子般」的比喻=秘密而輕盈\n「揭開蕾絲」是情感密度最高的一句，以動作隱喻親密", "3.2行動後果": "全曲的「後果」只是相會本身\n無任何痛苦、詛咒或失落", "3.3時間維度": "「Лишь только вечер затемнится синий」(當藍色的夜幕降臨)\n時間錨定在這個特定的夜晚", "3.4情感強度等級": "行動後果內斂＋當下爆發＋敘述性表達\n17首中情感最輕盈的曲目之一，以期待與秘密為核心"}, "lyrics": "Лишь только вечер затемнится синий,\n當藍色的夜幕降臨，\nЛишь только звезды зажгут небеса,\n當星辰點亮天際，\nИ черемух серебряный иней\n而稠李樹銀白的霜霧\nЖемчугами украсит роса,\n立刻被露珠裝點如珍珠，\nОтвори потихоньку калитку，\n請輕輕打開那小柵門，\nИ войди в тихий садик, как тень,\n如影子般步入靜謐的花園，\nНе забудь потемнее накидку,\n別忘了披上深色的斗篷，\nКружева на головку надень.\n在頭上戴好蕾絲。\nТам, где гуще сплетаются ветки,\n在那枝葉交織更密處，\nЯ незримо, неслышно пройду.\n我將無形無聲地走過。\nИ на самом пороге беседки\n而在那亭檻邊\nС милых уст кружева отведу.\n我將揭開甜美唇上的蕾絲。\nОтвори потихоньку калитку\n請輕輕打開那小柵門，\nИ войди в тихий садик, как тень.\n如影子般步入靜謐的花園。\nНе забудь потемнее накидку,\n別忘了披上深色的斗篷，\nКружева на головку надень.\n在頭上戴好蕾絲。"}, {"id": 23, "batch": 2, "sheet": "範例11 Душа 心靈", "full_title": "範例11 Душа 心靈", "title_ru": "Душа", "title_zh": "心靈", "motif": "義務與激情", "analysis": {"1.1情感關鍵詞": {"指標": "愛戀類、痛苦類（愛=命運=痛苦，三者不可分）", "分類": "▪ 愛戀類詞彙\n▪ 痛苦類詞彙"}, "1.2行動關鍵詞": {"指標": "無法行動（只能承受痛苦）", "分類": "▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "身體意象（靈魂流血）＋自然意象（路塵）", "分類": "▪ 物品意象\n▪ 自然意象"}, "2.1敘事視角": {"指標": "第一人稱（愛與痛苦無法分割的人）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（半宣告半質問）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（反覆宣告愛=受苦的閉環）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "悲劇結局偏和解（接受愛=受苦的宿命）", "分類": "▪ 悲劇結局（死亡／永遠分離）\n▪ 和解結局（放下／祝福）"}, "3.1情感表現方式": {"指標": "直接宣告＋獨特意象（笨拙的流血靈魂）", "分類": "▪ 直接高昂吶喊／控訴\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "中度（宣告愛與受苦的宿命，以質問呼告愛人）", "分類": "▪ 中度：生病"}, "3.3時間維度": {"指標": "永恆性（愛=命運，是一生的枷鎖）", "分類": "▪ 永恆性（永遠／一生）"}, "3.4情感強度等級": {"指標": "中度（以笨拙流血的靈魂意象表達愛與痛的合一）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「Я люблю тебя, ты — судьба моя」(我愛你，你是我的命運)\n「без тебя мне жизнь моя опостылая」(沒有你，我的生命變得可憎)\n「кровью капая」(滴著鮮血)——愛情以流血的靈魂表達", "1.2行動關鍵詞": "「без любви мне жить — только маяться」(沒有愛的生活，只是受苦)\n全曲無外在行動，只有「繼續愛、繼續受苦」的被動承受\n「не случилось бы со мной невозможное」(但願不可能的事不會發生在我身上)——唯一的祈求", "1.3意象關鍵詞": "身體：「ты — душа моя косолапая」(你是我笨拙的靈魂)——將愛人比作自己的靈魂\n「кровью капая в пыль дорожную」(滴血落入路塵)——愛情傷害流入日常生活的塵埃中\n極為獨特的意象——靈魂笨拙地流血", "2.1敘事視角": "「Я люблю тебя, ты — судьба моя」\n「без любви мне жить — только маяться」\n全程以「我」的愛與痛苦為核心", "2.2傾訴對象": "「Ты — душа моя косолапая」(你是我笨拙的靈魂)\n「Что болишь ты у меня, кровью капая?」(為何你在我心中如此疼痛，滴著鮮血？)\n以質問的語氣呼告愛人，既是愛慕也是痛苦的指控", "2.3情節發展": "「愛你→你是命運→沒有愛只是受苦」的反覆循環\n「這就是我們，你和我之間的結果」——以宿命語氣接受閉環", "2.4結局類型": "「так у нас, у нас с тобой получается」(這就是我們之間的結果)——宿命式的接受\n「不可能的事但願不要發生」——矛盾的祈求", "3.1情感表現方式": "「Я люблю тебя」的直接宣告\n「душа моя косолапая, кровью капая」——17首中最獨特的意象，笨拙流血的靈魂", "3.2行動後果": "「кровью капая」(滴著鮮血)——中度的身體化痛苦\n全曲無外在行動，內在的痛苦宣告達中度", "3.3時間維度": "「ты — судьба моя」(你是我的命運)——命運等同永恆\n「так у нас...получается」(這就是我們之間的結果)——以宿命語氣確認永恆", "3.4情感強度等級": "行動後果中度＋永恆性＋直接宣告\n意象密度高，「笨拙的靈魂」為本曲最獨特的貢獻"}, "lyrics": "Я люблю тебя, ты - судьба моя\n我愛你，你是我的命運\nБез тебя мне жизнь моя\n沒有你，我的生命\nОпостылая\n變得可憎\nБез любви мне жить - только маяться\n沒有愛的生活---只是受苦\nТак у нас, у нас с тобой получается\n這就是我們，你和我之間的結果\nБез любви мне жить - только маяться\n沒有愛的生活---只是受苦\nТак у нас, у нас с тобой получается\n這就是我們，你和我之間的結果\nТы - душа моя косолапая,\n你是我笨拙的靈魂，\nЧто болишь ты у меня,\n為何你在我心中如此疼痛，\nКровью капая?\n滴著鮮血？\nКровью капая в пыль дорожную?\n滴血落入路塵？\nНе случилось бы со мной невозможное\n但願不可能的事不會發生在我身上\nБез любви мне жить - только маяться\n沒有愛的生活---只是受苦\nТак у нас, у нас с тобой получается\n這就是我們，你和我之間的結果"}, {"id": 24, "batch": 2, "sheet": "範例12 Только раз 僅有一次", "full_title": "範例12 Только раз 僅有一次", "title_ru": "Только раз", "title_zh": "僅有一次", "motif": "思念與痛苦", "analysis": {"1.1情感關鍵詞": {"指標": "思念類、愛戀類（一生僅此一次的相遇已成失去）", "分類": "▪ 思念類詞彙\n▪ 愛戀類詞彙"}, "1.2行動關鍵詞": {"指標": "尋找/追問（找尋消失的愛人）", "分類": "▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "自然意象（晚霞/灌木/冬夜）為核心", "分類": "▪ 自然意象"}, "2.1敘事視角": {"指標": "第一人稱（失去後追憶的人）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（以問句追尋消失的「妳」）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（日夜思念→追問消失的愛人→重申唯一性）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "悲劇結局（愛人已消失，問題無回應）", "分類": "▪ 悲劇結局（死亡／永遠分離）"}, "3.1情感表現方式": {"指標": "敘述性表達＋自然意象隱喻（晚霞消逝=愛情消逝）", "分類": "▪ 敘述性表達\n▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "內斂（只有問句追尋）", "分類": "▪ 內斂：思念／沉默／等待"}, "3.3時間維度": {"指標": "永恆性（一生僅一次的宿命宣告）", "分類": "▪ 永恆性（永遠／一生）"}, "3.4情感強度等級": {"指標": "內斂偏中（以宿命宣告承載失去的遺憾）", "分類": "▪ 內斂"}}, "evidence": {"1.1情感關鍵詞": "「只раз бывает в жизни встреча」(一生僅有一次相遇)\n「только раз судьбою рвется нить」(命運之線僅此一次斷裂)\n「где же ты, желанная когда-то」(妳在哪裡，曾經渴望的人)——以「曾經」暗示已失去", "1.2行動關鍵詞": "「Где же ты, желанная когда-то, Где же ты, дарившая мечты?」(妳在哪裡？)\n以問句作為唯一的行動，追問消失的愛人", "1.3意象關鍵詞": "自然：「гаснет луч пурпурного заката」(紫色晚霞的光芒漸逝)——消逝的愛情\n「синевой окутаны кусты」(灌木叢被藍色暮靄籠罩)——憂鬱的自然背景\n「холодный зимний вечер」(寒冷的冬夜)——孤獨的時間意象", "2.1敘事視角": "「мне так хочется любить」(我如此渴望去愛)\n「день и ночь кружится голова」(日夜頭腦暈眩)——以身體感受表達思念", "2.2傾訴對象": "「Где же ты, желанная когда-то?」——問句對著不在場的愛人\n愛人已消失，呼告是對著虛空", "2.3情節發展": "全曲在「一生僅有一次」的宣告與追問「妳在哪裡」之間循環\n無事件，只有思念的反覆", "2.4結局類型": "「судьбою рвется нить」(命運之線斷裂)——不可挽回的分離\n「где же ты」(妳在哪裡)——問句無回應，愛人已消失", "3.1情感表現方式": "「гаснет луч пурпурного заката」——晚霞消逝=一生唯一相遇的消逝\n「день и ночь кружится голова」——以頭暈表達思念的持續", "3.2行動後果": "「Где же ты?」是全曲最強的行動\n無離開、無詛咒、只有思念與追問", "3.3時間維度": "「только раз бывает в жизни встреча」(一生僅有一次)\n「только раз судьбою рвется нить」——命運的唯一性宣告", "3.4情感強度等級": "行動後果內斂＋永恆性＋敘述性表達\n情感以「一生僅一次」的莊嚴語氣包裹，非哭泣也非吶喊"}, "lyrics": "День и ночь роняет сердце ласку,\n日夜不息，心臟輕吐著柔情\nДень и ночь кружится голова,\n日夜不息，頭腦暈眩恍惚\nДень и ночь взволнованною сказкой\n日夜不息，如激動的童話\nМне звучат твои слова.\n你的話語在我耳邊迴響\nТолько раз бывает в жизни встреча,\n一生僅有一次相遇\nТолько раз судьбою рвется нить,\n命運之線僅此一次斷裂\nТолько раз в холодный зимний вечер\n僅此一回在寒冷的冬夜\nМне так хочется любить.\n我如此渴望去愛\nГаснет луч пурпурного заката,\n紫色晚霞的光芒漸逝\nСиневой окутаны кусты.\n灌木叢被藍色暮靄籠罩\nГде же ты, желанная когда-то,\n妳在哪裡，曾經渴望的人\nГде же ты, дарившая мечты?\n妳在哪裡，贈我夢想的人？\nТолько раз бывает в жизни встреча,\n一生僅有一次相遇\nТолько раз судьбою рвется нить,\n命運之線僅此一次斷裂\nТолько раз в холодный зимний вечер\n僅此一回在寒冷的冬夜\nМне так хочется любить.\n我如此渴望去愛\nТолько раз бывает в жизни встреча,\n一生僅有一次相遇\nТолько раз судьбою рвется нить,\n命運之線僅此一次斷裂\nТолько раз в холодный зимний вечер\n僅此一回在寒冷的冬夜\nМне так хочется любить.\n我如此渴望去愛"}, {"id": 25, "batch": 2, "sheet": "範例13 Отцвели хризантемы 凋謝的菊花", "full_title": "範例13 Отцвели хризантемы 凋謝的菊花", "title_ru": "Отцвели хризантемы", "title_zh": "凋謝的菊花", "motif": "思念與痛苦", "analysis": {"1.1情感關鍵詞": {"指標": "思念類、痛苦類（愛人已去，花開花謝的對比）", "分類": "▪ 思念類詞彙\n▪ 痛苦類詞彙"}, "1.2行動關鍵詞": {"指標": "哭泣/等待（獨自徘徊，在枯萎菊花前流淚）", "分類": "▪ 哭泣／祈求"}, "1.3意象關鍵詞": {"指標": "自然意象（菊花開謝）為絕對核心", "分類": "▪ 自然意象"}, "2.1敘事視角": {"指標": "第一人稱（被留下的人，在廢園中徘徊）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（以вы敬稱，帶有尊敬與懷念）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "有明確情節轉折（相遇時菊花盛開→愛情綻放→如今菊花凋謝，愛人已去，我獨自流淚）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "悲劇結局（愛人已去，只剩流淚的我與枯萎的花）", "分類": "▪ 悲劇結局（死亡／永遠分離）"}, "3.1情感表現方式": {"指標": "隱喻/暗示（菊花開謝=愛情週期）＋敘述性表達", "分類": "▪ 隱喻／暗示\n▪ 敘述性表達"}, "3.2行動後果": {"指標": "中度（徘徊、流淚，無法承受失去）", "分類": "▪ 中度：哭泣／生病"}, "3.3時間維度": {"指標": "持續性（從相遇時的菊花盛開到如今的凋謝）", "分類": "▪ 持續性（一段時間）"}, "3.4情感強度等級": {"指標": "中度（以花的枯謝承載靜默的悲傷）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「любовь все живет в моем сердце больном」(愛情依然存活在我痛苦的心裡)\n「я брожу один весь измученный」(我獨自徘徊，疲憊不堪)\n「невольные слезы катятся」(不由自主的淚水滾落)", "1.2行動關鍵詞": "「Я брожу один весь измученный」(我獨自徘徊，疲憊不堪)\n「невольные слезы катятся пред увядшим кустом хризантем」\n(不由自主的淚水滾落，在枯萎的菊花叢前)\n以徘徊與流淚作為情感行動", "1.3意象關鍵詞": "「хризантемы расцвел」(菊花盛開)——相遇時的愛情綻放\n「отцвели уж давно хризантемы в саду」(菊花早已凋謝)——愛情已逝\n「опустел наш сад」(花園已荒蕪)——關係的徹底結束\n花開花謝的意象=愛情由盛到衰的完整隱喻", "2.1敘事視角": "「В том саду, где мы с вами встретились」(在我們相遇的花園裡)\n「Я брожу один весь измученный」(我獨自徘徊)", "2.2傾訴對象": "「вас давно уж нет」(您早已離去)——以вы稱呼\n「ваш любимый куст хризантем расцвел」(您最愛的菊花叢盛開)——以「您最愛的」連結愛人", "2.3情節發展": "過去：在有菊花的花園相遇，胸中的愛也一起綻放\n現在：菊花早已凋謝，花園荒蕪，愛人已去\n行動：我在枯萎菊花前不由自主流淚", "2.4結局類型": "「вас давно уж нет」(您早已離去)\n「невольные слезы катятся пред увядшим кустом хризантем」\n以枯萎菊花前的淚水作結，無任何和解", "3.1情感表現方式": "菊花的盛開與凋謝是全曲最完整的隱喻系統\n「отцвели уж давно」的反覆強調凋謝的不可逆\n「сердце больном」(痛苦的心)——身體化的悲傷表達", "3.2行動後果": "「невольные слезы катятся」(不由自主的淚水滾落)——中度的哭泣\n「весь измученный」(疲憊不堪)——情感已耗盡身體", "3.3時間維度": "過去菊花盛開對比現在凋謝——時間跨度明確\n「любовь все живет」(愛情依然存活)——持續的情感", "3.4情感強度等級": "行動後果中度（哭泣/徘徊）＋持續性＋隱喻表達\n菊花意象系統的完整性是本曲的核心貢獻"}, "lyrics": "В том саду, где мы с вами встретились,\n在那座我們相遇的花園裡，\nВаш любимый куст хризантем расцвел,\n您最愛的菊花叢已然盛開，\nИ в моей груди расцвело тогда\n而在我胸中那時也綻放了\nЧувство яркое нежной любви...\n鮮明而溫柔的愛戀之情...\nОтцвели уж давно\n花園中的菊花\nХризантемы в саду,\n早已凋謝\nНо любовь все живет\n但愛情依然存活\nВ моем сердце больном...\n在我痛苦的心裡...\nОтцвели уж давно\n花園中的菊花\nХризантемы в саду...\n早已凋謝\nОпустел наш сад, вас давно уж нет,\n我們的花園已荒蕪，您早已離去，\nЯ брожу один весь измученный,\n我獨自徘徊，疲憊不堪，\nИ невольные слезы катятся\n而不由自主的淚水滾落\nПред увядшим кустом хризантем...\n在枯萎的菊花叢前..."}, {"id": 26, "batch": 2, "sheet": "範例15 Тонкая рябина 纖細的花楸樹", "full_title": "範例15 Тонкая рябина 纖細的花楸樹", "title_ru": "Тонкая рябина", "title_zh": "纖細的花楸樹", "motif": "思念與痛苦", "analysis": {"1.1情感關鍵詞": {"指標": "思念類（以自然寓言表達不可能的渴望）", "分類": "▪ 思念類詞彙"}, "1.2行動關鍵詞": {"指標": "渴望靠近（但無法移動）", "分類": "▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "自然意象（花楸樹/橡樹）為全曲唯一核心", "分類": "▪ 自然意象"}, "2.1敘事視角": {"指標": "第三人稱→第一人稱（旁觀者描述→花楸樹自述渴望）", "分類": "▪ 第三人稱（他／她）\n▪ 混合視角"}, "2.2傾訴對象": {"指標": "對聽眾（問句式的旁觀呼告）", "分類": "▪ 對聽眾"}, "2.3情節發展": {"指標": "有明確情節（花楸搖曳→渴望靠近橡樹→但無法跨越道路與河流→宿命孤獨）", "分類": "▪ 有明確情節轉折"}, "2.4結局類型": {"指標": "悲劇結局（宿命的孤獨，永遠無法靠近）", "分類": "▪ 悲劇結局（死亡／永遠分離）"}, "3.1情感表現方式": {"指標": "隱喻/暗示（自然寓言=全曲核心表現方式）", "分類": "▪ 隱喻／暗示"}, "3.2行動後果": {"指標": "內斂（無法行動，只有假設語氣的渴望）", "分類": "▪ 內斂：思念／沉默／等待"}, "3.3時間維度": {"指標": "永恆性（命定永遠獨自搖曳）", "分類": "▪ 永恆性（永遠／一生）"}, "3.4情感強度等級": {"指標": "內斂（以宿命的自然寓言表達無聲的孤獨）", "分類": "▪ 內斂"}}, "evidence": {"1.1情感關鍵詞": "「как бы мне, рябине, к дубу перебраться」(我多麼想能移到橡樹身旁)\n「я тогда б не стала гнуться и качаться」(那時我就不必再彎腰和搖曳)\n「знать, ей сиротине век одной качаться」(她命定永遠獨自搖曳)——宿命的孤獨", "1.2行動關鍵詞": "「тонкими ветвями я б к нему прижалась」(我要用纖細的枝條緊緊依偎他)——假設語氣\n「с его листвою день и ночь шепталась」(與他的樹葉日夜細語)——假設的親密\n所有行動都是假設語氣，現實中無法實現", "1.3意象關鍵詞": "「тонкая рябина」(纖細的花楸樹)——弱小、孤獨、渴望依靠的女性象徵\n「高大的橡樹」——對岸的強壯男性象徵\n「дорога和寬闊的河流」——不可逾越的障礙\n完全以自然意象構成的寓言系統", "2.1敘事視角": "第三人稱開頭：「什麼搖曳站立，垂頭至籬笆邊」\n轉為第一人稱：「我多麼想能移到橡樹身旁...我要用枝條依偎他」\n最後回到宿命陳述：「她命定永遠獨自搖曳」", "2.2傾訴對象": "「Что стоишь качаясь, тонкая рябина?」(你為何搖曳站立，纖細的花楸樹？)\n以問句開場，帶有旁觀者向自然詢問的語氣", "2.3情節發展": "花楸樹搖曳垂首\n想像若能靠近橡樹就不必搖曳\n現實：無法跨越道路與河流\n宿命：永遠獨自搖曳的孤兒", "2.4結局類型": "「нельзя рябине к дубу перебраться」(花楸樹無法移到橡樹身邊)\n「знать, ей сиротине век одной качаться」(她命定永遠獨自搖曳)\n以「宿命/век」(整個人生)的永恆性確認悲劇", "3.1情感表現方式": "全曲唯一的表現方式就是自然寓言\n從不直接說「我愛你」或「我很孤獨」\n以花楸樹的搖曳、橡樹的遙遠、道路的阻隔承載所有情感", "3.2行動後果": "「我要用枝條依偎他」——假設語氣，從未實現\n唯一的「行動」是繼續搖曳——被動的宿命", "3.3時間維度": "「сиротине век одной качаться」(孤兒命定永遠獨自搖曳)\n「век」=整個生命的時間跨度", "3.4情感強度等級": "行動後果內斂＋永恆性＋純隱喻表達\n17首中意象最純粹、語言最克制的曲目，以自然完全取代人的情感陳述"}, "lyrics": "Что стоишь качаясь, тонкая рябина,\n纖細的花楸樹，你為何搖曳站立，\nГоловой склоняясь до самого тына,\n將頭垂至籬笆邊，\nГоловой склоняясь до самого тына.\n將頭垂至籬笆邊。\nА через дорогу, за рекой широкой,\n而在道路對面，寬闊的河流後，\nТакже одиноко дуб стоит высокий.\n同樣孤獨地矗立著高大的橡樹。\nКак бы мне, рябине, к дубу перебраться,\n我多麼想，花楸樹啊，能移到橡樹身旁，\nЯ тогда б не стала гнуться и качаться,\n那時我就不必再彎腰和搖曳，\nЯ тогда б не стала гнуться и качаться.\n那時我就不必再彎腰和搖曳。\nТонкими ветвями я б к нему прижалась\n我要用纖細的枝條緊緊依偎他\nИ с его листвою день и ночь шепталась.\n與他的樹葉日夜不停地細語。\nНо нельзя рябине к дубу перебраться,\n但花楸樹無法移到橡樹身邊，\nЗнать, ей сиротине век одной качаться,\n可知，她這孤兒命定永遠獨自搖曳，\nЗнать, ей сиротине век одной качаться.\n可知，她這孤兒命定永遠獨自搖曳。"}, {"id": 27, "batch": 2, "sheet": "範例16 Я люблю тебя больше 我愛妳勝過一", "full_title": "範例16 Я люблю тебя больше природы 我愛妳勝過愛大自然", "title_ru": "Я люблю тебя больше природы", "title_zh": "我愛妳勝過愛大自然", "motif": "義務與激情", "analysis": {"1.1情感關鍵詞": {"指標": "愛戀類（以超越一切作為宣告方式）", "分類": "▪ 愛戀類詞彙"}, "1.2行動關鍵詞": {"指標": "宣告（持續升級的愛的宣言）", "分類": "▪ 訴說／沉默"}, "1.3意象關鍵詞": {"指標": "文化意象（莎士比亞/音樂）＋自然意象（大自然/自由）", "分類": "▪ 自然意象\n▪ 物品意象"}, "2.1敘事視角": {"指標": "第一人稱（熾烈宣告者）", "分類": "▪ 第一人稱（我）"}, "2.2傾訴對象": {"指標": "對愛人（ты，直接宣告）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（愛的宣言持續升級）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "開放式偏積極（宣告永不結束，愛超越一切）", "分類": "▪ 開放式結局（未知）\n▪ 和解結局（放下／祝福）"}, "3.1情感表現方式": {"指標": "直接高昂吶喊（反覆的比較式宣告）", "分類": "▪ 直接高昂吶喊／控訴"}, "3.2行動後果": {"指標": "中度（以語言宣告征服一切，無外在行動）", "分類": "▪ 中度：祈求"}, "3.3時間維度": {"指標": "永恆性（盲目地、無限期地愛著）", "分類": "▪ 永恆性（永遠／一生）"}, "3.4情感強度等級": {"指標": "強烈（語言爆發最強，以宣告征服一切）", "分類": "▪ 強烈"}}, "evidence": {"1.1情感關鍵詞": "「Я люблю тебя больше природы / свободы / Шекспира」(勝過大自然/自由/莎士比亞)\n「больше, чем можно / чем невозможно」(勝過一切可能/不可能)\n「больше Любви」(勝過對愛情的愛)——愛的極限超越了愛本身的定義", "1.2行動關鍵詞": "全曲以宣告為核心行動\n「ибо ты — как природа сама」(因為妳就是自然本身)\n「ибо книга и музыка — ты!」(因為妳就是詩篇與樂章)", "1.3意象關鍵詞": "大自然、自由、莎士比亞、全世界音樂——所有偉大事物均被納入比較範疇\n「без тебя и свобода — тюрьма」(沒有妳，自由也是監獄)——最強烈的比喻\n「даже пьянствуя, даже грубя!」(即使酩酊大醉，即使粗暴無禮！)——愛的不完美性", "2.1敘事視角": "「Я люблю тебя」反覆出現的第一人稱宣告\n「я люблю безоглядно, бессрочно!」(我盲目地、無限期地愛著！)", "2.2傾訴對象": "「Я люблю тебя больше природы」——直接對著「你/妳」宣告\n「ты несчастен! Ты просишь у счастья участья」(妳不幸！妳向幸福祈求憐憫)——直接指向對方", "2.3情節發展": "全曲是一個不斷升級的愛的宣言\n每一段都加大比較的對象，從自然→自由→莎士比亞→所有音樂→幸福本身→愛情本身", "2.4結局類型": "「Я люблю тебя больше природы / свободы」作為結尾的回歸\n以愛超越一切的宣言收尾，無悲劇", "3.1情感表現方式": "全曲以「我愛妳勝過X」的句式反覆高昂吶喊\n「больше, чем невозможно」(超越不可能的極限)——語言本身已超越邊界", "3.2行動後果": "全曲行動只有「宣告」\n但宣告的強度達到「愛妳勝過愛情本身」的邏輯極限", "3.3時間維度": "「безоглядно, бессрочно!」(盲目地、無限期地)\n「без тебя и свобода — тюрьма」——永恆的依存", "3.4情感強度等級": "行動後果中度但語言強度達強烈\n「愛妳勝過愛情本身」是全17首中語言上最激進的宣告"}, "lyrics": "我愛妳勝過愛大自然，\nИбо ты - как природа сама.\n因為妳就是自然本身。\nЯ люблю тебя больше свободы,\n我愛妳勝過愛自由，\nБез тебя и свобода -- тюрьма.\n沒有妳，自由也是監獄。\nЯ люблю тебя неосторожно,\n我愛妳如此不顧一切，\nСловно пропасть, а не колею.\n如同墜入深淵而非平坦。\nЯ люблю тебя больше, чем можно.\n我愛妳勝過一切可能。\nБольше, чем невозможно, люблю.\n我愛妳超越不可能的極限。\nЯ люблю безоглядно, бессрочно!\n我盲目地、無限期地愛著！\nДаже пьянствуя, даже грубя!\n即使酩酊大醉，即使粗暴無禮！\nИ уж больше себя -- это точно.\n而且勝過愛自己------這是肯定的。\nДаже больше, чем просто тебя.\n甚至勝過單純地愛妳。\nЯ люблю тебя больше Шекспира!\n我愛妳勝過莎士比亞！\nБольше всей на Земле красоты.\n勝過對世上一切美的熱愛。\nдаже больше всей музыки мира,\n甚至勝過全世界所有音樂，\nИбо книга и музыка -- ты.\n因為妳就是詩篇與樂章。\nЯ люблю безоглядно, бессрочно!\n我盲目地、無限期地愛著！\nДаже пьянствуя, даже грубя!\n即使酩酊大醉，即使粗暴無禮！\nИ уж больше себя -- это точно.\n而且勝過愛自己------這是肯定的。\nДаже больше, чем просто тебя.\n甚至勝過單純地愛妳。\nЯ люблю тебя больше Шекспира!\n我愛妳勝過莎士比亞！\nБольше всей на Земле красоты.\n勝過對世上一切美的熱愛。\nдаже больше всей музыки мира,\n甚至勝過全世界所有音樂，\nИбо книга и музыка -- ты!\n因為妳就是詩篇與樂章！\nТы несчастен! Ты просишь у счастья участья.\n妳不幸！妳向幸福祈求憐憫。\nБога просьбами, ты - не гневи.\n別用祈求觸怒上帝。\nЯ люблю тебя больше Счастья,\n我愛妳勝過愛幸福，\nЯ люблю тебя больше Любви.\n我愛妳勝過對愛情的愛。\nТы несчастен! Ты просишь у счастья участья.\n妳不幸！妳向幸福祈求憐憫。\nБога просьбами, ты - не гневи.\n別用祈求觸怒上帝。\nЯ люблю тебя больше Счастья.\n我愛妳勝過愛幸福。\nЯ люблю тебя больше Любви.\n我愛妳勝過對愛情的愛。\nЯ люблю тебя больше Природы.\n我愛妳勝過愛大自然。\nЯ люблю тебя больше Свободы.\n我愛你勝過愛自由。\nИбо без тебя и свобода -- тюрьма.\n因為沒有妳，自由也是監獄。"}, {"id": 28, "batch": 2, "sheet": "範例17 Очарована 痴迷沉醉", "full_title": "範例17 Очарована 痴迷沉醉", "title_ru": "Очарована", "title_zh": "痴迷沉醉", "motif": "義務與激情", "analysis": {"1.1情感關鍵詞": {"指標": "愛戀類、沉淪類（被迷魅束縛的女性，男性的凝視與渴望）", "分類": "▪ 愛戀類詞彙\n▪ 沉淪類詞彙"}, "1.2行動關鍵詞": {"指標": "俯身/擁抱（男性主動的愛意表達）", "分類": "▪ 哭泣／祈求"}, "1.3意象關鍵詞": {"指標": "自然意象（原野之風/幽暗天穹）＋物品意象（枷鎖/星辰）", "分類": "▪ 自然意象\n▪ 物品意象"}, "2.1敘事視角": {"指標": "第一人稱（男性凝視者，描述被迷魅的女子）", "分類": "▪ 第一人稱（我）\n▪ 混合視角"}, "2.2傾訴對象": {"指標": "對愛人（描述她的狀態，同時宣告自己的愛）", "分類": "▪ 對愛人"}, "2.3情節發展": {"指標": "無明顯情節，只有情緒（凝視被迷魅的她→承諾俯身擁抱→質問她為何哭泣）", "分類": "▪ 無明顯情節，只有情緒"}, "2.4結局類型": {"指標": "開放式（她為何哭泣未解，或許是幻覺）", "分類": "▪ 開放式結局（未知）"}, "3.1情感表現方式": {"指標": "隱喻/暗示（枷鎖/風的姻緣/幽暗天穹）＋直接宣告", "分類": "▪ 隱喻／暗示\n▪ 直接高昂吶喊／控訴"}, "3.2行動後果": {"指標": "中度（以狂熱的力量俯身擁抱，流淚）", "分類": "▪ 中度：哭泣／祈求"}, "3.3時間維度": {"指標": "當下爆發（凝視她的此刻，承諾的此刻）", "分類": "▪ 當下爆發（此時此刻）"}, "3.4情感強度等級": {"指標": "中度（以狂熱擁抱為頂點，末尾留下幻覺式的不確定）", "分類": "▪ 中度"}}, "evidence": {"1.1情感關鍵詞": "「очарована, околдована」(痴迷沉醉，心神俱醉)——反覆的被動語態\n「вся ты словно в оковы закована」(妳彷彿身披層層枷鎖)——愛情=枷鎖\n「звезда ты моя сумасшедшая」(妳是我瘋狂的星辰)——以瘋狂形容對她的愛", "1.2行動關鍵詞": "「Я склонюсь над твоими коленями」(我將俯身於妳的膝前)\n「Обниму их с неистовой силою」(以狂熱的力量擁抱它們)\n「слезами и поцелуями обниму тебя」(用淚水與親吻將妳擁抱)\n以肢體行動承載情感", "1.3意象關鍵詞": "自然：「с ветром в поле когда-то повенчана」(曾與原野之風締結姻緣)——吉普賽女性命運的象徵\n「словно с темного неба сошедшая」(宛如自幽暗天穹翩然降臨)\n物品：「枷鎖」——愛情的束縛；「訂婚的歌曲」——情感的儀式化", "2.1敘事視角": "「Я склонюсь...Обниму тебя」——第一人稱的主動行動\n但大量篇幅在描述「她」的狀態（痴迷、枷鎖、與風締結姻緣）\n男性視角凝視被迷魅的女性", "2.2傾訴對象": "「драгоценная ты моя женщина!」(我珍貴無比的女子啊！)\n「так чего же ты плачешь, красавица?」(那妳為何哭泣呢，我的美人？)——直接問她", "2.3情節發展": "全曲停留在凝視與承諾的瞬間\n「что не сбудется — позабудется」(未能實現的，終將被遺忘)——帶有淡淡的無常感\n末尾的「妳為何哭泣？」懸而未解", "2.4結局類型": "「или мне это просто чудится?..」(抑或這只是我的幻覺？)\n以不確定性收尾——她是否真的哭泣，還是男主的幻想？", "3.1情感表現方式": "「очарована, околдована」——反覆的被動語態描述她的被迷魅狀態\n「обниму их с неистовой силою」(以狂熱的力量擁抱)——直接的強烈情感表達\n「枷鎖/瘋狂的星辰」——豐富的隱喻", "3.2行動後果": "「Обниму их с неистовой силою」(以狂熱的力量擁抱)——中度的情感行動\n「слезами и поцелуями」(淚水與親吻)——情感外化", "3.3時間維度": "「я склонюсь...обниму...」——未來式但指向即將發生的此刻\n「сегодня нитью тонкою」式的當下連結感", "3.4情感強度等級": "行動後果中度（擁抱/流淚）＋當下爆發＋隱喻豐富\n末尾「或許是幻覺」的不確定使強度收斂"}, "lyrics": "Очарована, околдована,\n痴迷沉醉，心神俱醉，\nС ветром в поле когда-то повенчана,\n曾與原野之風締結姻緣。\nВся ты словно в оковы закована,\n妳彷彿身披層層枷鎖，\nДрагоценная ты моя женщина!\n我珍貴無比的女子啊！\nНе веселая, не печальная,\n不見歡欣，亦無悲切，\nСловно с темного неба сошедшая,\n宛如自幽暗天穹翩然降臨，\nТы и песнь моя обручальная,\n妳是我那訂婚的歌曲，\nИ звезда ты моя сумасшедшая…\n也是我瘋狂的星辰......\nЯ склонюсь над твоими коленями,\n我將俯身於妳的膝前，\nОбниму их с неистовой силою,\n以狂熱的力量擁抱它們，\nИ слезами и поцелуями\n用淚水與親吻\nОбниму тебя, добрую, милую…\n將妳擁抱，善良又可愛的人......\nЧто не сбудется - позабудется,\n未能實現的，終將被遺忘，\nЧто не вспомнится - то не исполнится.\n未能被憶起的，便不會成真。\nТак чего же ты плачешь, красавица,\n那妳為何哭泣呢，我的美人？\nИли мне это просто чудится?..\n抑或這只是我的幻覺？..\nОчарована, околдована,\n痴迷沉醉，心神俱醉，\nС ветром в поле когда-то повенчана,\n曾與原野之風締結姻緣。\nВся ты словно в оковы закована,\n妳彷彿身披層層枷鎖，\nДрагоценная ты моя женщина!\n我珍貴無比的女子啊！"}];
